   236тЖТ
   237тЖТ      for (let cycle = 1; cycle <= cyclesCompleted; cycle++) {
   238тЖТ        const targetMileage = cycle * pmType.intervalKm;
   239тЖТ
   240тЖТ        // Calculate when this mileage was reached
   241тЖТ        const daysToReach = Math.round((targetMileage - lastPmMileage) / train.estimatedDailyKm);
