     1тЖТ/**
     2тЖТ * MMS Demo CSV Import Module
     3тЖТ *
     4тЖТ * Parses client-provided CSV files (Maximo exports) for the demo application.
     5тЖТ * Supports Fleet Roster, PM History, and PM Rules CSVs per spec 009 Section 9.2.1.
     6тЖТ *
     7тЖТ * @example
     8тЖТ * ```typescript
     9тЖТ * import { parseFleetRosterCsv, parsePmHistoryCsv, importDemoData } from './csv-import';
    10тЖТ *
    11тЖТ * // Parse individual CSV strings
    12тЖТ * const roster = parseFleetRosterCsv(csvContent);
    13тЖТ * const history = parsePmHistoryCsv(csvContent);
    14тЖТ *
    15тЖТ * // Import complete demo data from multiple CSVs
    16тЖТ * const demoData = importDemoData({
    17тЖТ *   fleetRoster: rosterCsv,
    18тЖТ *   pmHistory: historyCsv,
    19тЖТ *   pmRules: rulesCsv, // optional, uses defaults if not provided
    20тЖТ * });
    21тЖТ * ```
    22тЖТ *
    23тЖТ * @see specs/009-demo-application.md Section 9.2.1
    24тЖТ */
    25тЖТ
    26тЖТimport * as Papa from 'papaparse';
    27тЖТimport {
    28тЖТ  parseFleetRosterCsvRow,
    29тЖТ  isValidDateString,
    30тЖТ  type ValidationError,
    31тЖТ} from '../lib/schemas';
    32тЖТimport { PM_RULES_BY_FLEET } from './data';
    33тЖТ
    34тЖТ// =============================================================================
    35тЖТ// Types
    36тЖТ// =============================================================================
    37тЖТ
    38тЖТ/** Imported train from Fleet Roster CSV */
    39тЖТexport interface ImportedTrain {
    40тЖТ  trainNumber: string;
    41тЖТ  fleetCode: string;
    42тЖТ  currentMileageKm: number;
    43тЖТ  commissioningDate: Date;
    44тЖТ  estimatedDailyKm: number;
    45тЖТ  confidence: 'HISTORICAL' | 'ESTIMATED';
    46тЖТ}
    47тЖТ
    48тЖТ/** Imported PM history record */
    49тЖТexport interface ImportedPMHistory {
    50тЖТ  trainNumber: string;
    51тЖТ  pmCode: string;
    52тЖТ  completionDate: Date;
    53тЖТ  mileageAtCompletion: number;
    54тЖТ}
    55тЖТ
    56тЖТ/** Imported PM rule */
    57тЖТexport interface ImportedPMRule {
    58тЖТ  fleetCode: string;
    59тЖТ  pmCode: string;
    60тЖТ  intervalKm: number;
    61тЖТ  intervalMonths: number | null;
    62тЖТ  durationDays: number;
    63тЖТ  estimatedHours: number;
    64тЖТ  satisfiesCodes: string[];
    65тЖТ}
    66тЖТ
    67тЖТ/** Complete fleet state from imported data */
    68тЖТexport interface FleetState {
    69тЖТ  trains: ImportedTrain[];
    70тЖТ  pmHistory: ImportedPMHistory[];
    71тЖТ  pmRules: ImportedPMRule[];
    72тЖТ}
    73тЖТ
    74тЖТ/** CSV parse result with detailed errors */
    75тЖТexport interface CsvParseResult<T> {
    76тЖТ  success: boolean;
    77тЖТ  data: T[];
    78тЖТ  errors: CsvParseError[];
    79тЖТ  warnings: string[];
    80тЖТ  stats: {
    81тЖТ    totalRows: number;
    82тЖТ    validRows: number;
    83тЖТ    invalidRows: number;
    84тЖТ    duplicatesRemoved: number;
    85тЖТ  };
    86тЖТ}
    87тЖТ
    88тЖТ/** Detailed parse error with row information */
    89тЖТexport interface CsvParseError {
    90тЖТ  row: number;
    91тЖТ  field: string;
    92тЖТ  message: string;
    93тЖТ  rawValue?: string;
    94тЖТ}
    95тЖТ
    96тЖТ/** Import options for customizing behavior */
    97тЖТexport interface ImportOptions {
    98тЖТ  /** Throw on first error (default: false, collect all errors) */
    99тЖТ  strict?: boolean;
   100тЖТ  /** Default commissioning date if not provided (default: 5 years ago) */
   101тЖТ  defaultCommissioningDate?: Date;
   102тЖТ  /** Daily km estimate if no PM history exists (default: 150 km/day) */
   103тЖТ  defaultDailyKm?: number;
   104тЖТ}
   105тЖТ
   106тЖТ// =============================================================================
   107тЖТ// Constants
   108тЖТ// =============================================================================
   109тЖТ
   110тЖТ/** Default daily km for trains without history */
   111тЖТconst DEFAULT_DAILY_KM = 150;
   112тЖТ
   113тЖТ/** Minimum commissioning date (sanity check) */
   114тЖТconst MIN_COMMISSIONING_DATE = new Date('2000-01-01');
   115тЖТ
   116тЖТ/** Valid PM codes per spec */
   117тЖТconst VALID_PM_CODES = ['C1', 'C2', 'C3', 'C4', 'C5', 'OH'];
   118тЖТ
   119тЖТ// =============================================================================
   120тЖТ// Fleet Roster CSV Parser
   121тЖТ// =============================================================================
   122тЖТ
   123тЖТ/**
   124тЖТ * Parse Fleet Roster CSV content
   125тЖТ *
   126тЖТ * Expected columns:
   127тЖТ * - train_number (required): Unique train identifier
   128тЖТ * - fleet_code (required): Fleet type (e.g., "KS", "ALSTOM")
   129тЖТ * - current_mileage_km (required): Current odometer reading
   130тЖТ * - commissioning_date (optional): YYYY-MM-DD format
   131тЖТ *
   132тЖТ * Validation rules per spec 009:
   133тЖТ * - train_number must be unique
   134тЖТ * - current_mileage_km must be > 0
   135тЖТ * - commissioning_date must be in the past
   136тЖТ */
   137тЖТexport function parseFleetRosterCsv(
   138тЖТ  csvContent: string,
   139тЖТ  options: ImportOptions = {}
   140тЖТ): CsvParseResult<ImportedTrain> {
   141тЖТ  const result: CsvParseResult<ImportedTrain> = {
   142тЖТ    success: true,
   143тЖТ    data: [],
   144тЖТ    errors: [],
   145тЖТ    warnings: [],
   146тЖТ    stats: { totalRows: 0, validRows: 0, invalidRows: 0, duplicatesRemoved: 0 },
   147тЖТ  };
   148тЖТ
   149тЖТ  const defaultDate =
   150тЖТ    options.defaultCommissioningDate ??
   151тЖТ    new Date(Date.now() - 5 * 365 * 24 * 60 * 60 * 1000); // 5 years ago
   152тЖТ
   153тЖТ  const parsed = Papa.parse<Record<string, string>>(csvContent, {
   154тЖТ    header: true,
   155тЖТ    skipEmptyLines: true,
   156тЖТ    transformHeader: (header) => header.trim().toLowerCase(),
   157тЖТ  });
   158тЖТ
   159тЖТ  if (parsed.errors.length > 0) {
   160тЖТ    for (const err of parsed.errors) {
   161тЖТ      result.errors.push({
   162тЖТ        row: err.row ?? 0,
   163тЖТ        field: 'csv',
   164тЖТ        message: err.message,
   165тЖТ      });
   166тЖТ    }
   167тЖТ    if (options.strict) {
   168тЖТ      result.success = false;
   169тЖТ      return result;
   170тЖТ    }
   171тЖТ  }
   172тЖТ
   173тЖТ  const seenTrainNumbers = new Set<string>();
   174тЖТ  result.stats.totalRows = parsed.data.length;
   175тЖТ
   176тЖТ  for (let i = 0; i < parsed.data.length; i++) {
   177тЖТ    const row = parsed.data[i];
   178тЖТ    const rowNum = i + 2; // +2 for header row and 0-based index
   179тЖТ
   180тЖТ    const parseResult = parseFleetRosterCsvRow(row);
   181тЖТ
   182тЖТ    if (!parseResult.success) {
   183тЖТ      result.stats.invalidRows++;
   184тЖТ      for (const err of parseResult.errors) {
   185тЖТ        result.errors.push({
   186тЖТ          row: rowNum,
   187тЖТ          field: err.field,
   188тЖТ          message: err.message,
   189тЖТ          rawValue: String(row[err.field] ?? ''),
   190тЖТ        });
   191тЖТ      }
   192тЖТ      if (options.strict) {
   193тЖТ        result.success = false;
   194тЖТ        return result;
   195тЖТ      }
   196тЖТ      continue;
   197тЖТ    }
   198тЖТ
   199тЖТ    const data = parseResult.data;
   200тЖТ
   201тЖТ    // Check for duplicate train numbers
   202тЖТ    if (seenTrainNumbers.has(data.trainNumber)) {
   203тЖТ      result.warnings.push(
   204тЖТ        `Row ${rowNum}: Duplicate train number '${data.trainNumber}' - keeping first occurrence`
   205тЖТ      );
   206тЖТ      result.stats.duplicatesRemoved++;
   207тЖТ      continue;
   208тЖТ    }
   209тЖТ    seenTrainNumbers.add(data.trainNumber);
   210тЖТ
   211тЖТ    // Validate mileage > 0
   212тЖТ    if (data.currentMileageKm <= 0) {
   213тЖТ      result.errors.push({
   214тЖТ        row: rowNum,
   215тЖТ        field: 'current_mileage_km',
   216тЖТ        message: 'Mileage must be greater than 0',
   217тЖТ        rawValue: String(data.currentMileageKm),
   218тЖТ      });
   219тЖТ      result.stats.invalidRows++;
   220тЖТ      if (options.strict) {
   221тЖТ        result.success = false;
   222тЖТ        return result;
   223тЖТ      }
   224тЖТ      continue;
   225тЖТ    }
   226тЖТ
   227тЖТ    // Parse commissioning date
   228тЖТ    let commissioningDate: Date;
   229тЖТ    if (data.commissioningDate && isValidDateString(data.commissioningDate)) {
   230тЖТ      commissioningDate = new Date(data.commissioningDate);
   231тЖТ
   232тЖТ      // Validate commissioning date is in the past
   233тЖТ      if (commissioningDate > new Date()) {
   234тЖТ        result.errors.push({
   235тЖТ          row: rowNum,
   236тЖТ          field: 'commissioning_date',
   237тЖТ          message: 'Commissioning date must be in the past',
   238тЖТ          rawValue: data.commissioningDate,
   239тЖТ        });
   240тЖТ        result.stats.invalidRows++;
   241тЖТ        if (options.strict) {
   242тЖТ          result.success = false;
   243тЖТ          return result;
   244тЖТ        }
   245тЖТ        continue;
   246тЖТ      }
   247тЖТ
   248тЖТ      // Sanity check: not before 2000
   249тЖТ      if (commissioningDate < MIN_COMMISSIONING_DATE) {
   250тЖТ        result.warnings.push(
   251тЖТ          `Row ${rowNum}: Unusually early commissioning date '${data.commissioningDate}'`
   252тЖТ        );
   253тЖТ      }
   254тЖТ    } else {
   255тЖТ      commissioningDate = defaultDate;
   256тЖТ      result.warnings.push(
   257тЖТ        `Row ${rowNum}: Missing commissioning date, using default (${defaultDate.toISOString().split('T')[0]})`
   258тЖТ      );
   259тЖТ    }
   260тЖТ
   261тЖТ    result.data.push({
   262тЖТ      trainNumber: data.trainNumber,
   263тЖТ      fleetCode: data.fleetCode.toUpperCase(),
   264тЖТ      currentMileageKm: data.currentMileageKm,
   265тЖТ      commissioningDate,
   266тЖТ      estimatedDailyKm: options.defaultDailyKm ?? DEFAULT_DAILY_KM,
   267тЖТ      confidence: 'ESTIMATED',
   268тЖТ    });
   269тЖТ    result.stats.validRows++;
   270тЖТ  }
   271тЖТ
   272тЖТ  result.success = result.stats.invalidRows === 0 || !options.strict;
   273тЖТ  return result;
   274тЖТ}
   275тЖТ
   276тЖТ// =============================================================================
   277тЖТ// PM History CSV Parser
   278тЖТ// =============================================================================
   279тЖТ
   280тЖТ/**
   281тЖТ * Parse PM History CSV content
   282тЖТ *
   283тЖТ * Expected columns (per spec 009):
   284тЖТ * - train_number (required): References fleet roster
   285тЖТ * - pm_code (required): PM type (C1, C2, C3, C4, C5, OH)
   286тЖТ * - completion_date (required): YYYY-MM-DD format
   287тЖТ * - mileage_at_completion (optional but recommended): Odometer at completion
   288тЖТ *
   289тЖТ * Validation rules per spec 009:
   290тЖТ * - train_number should exist in fleet roster (warning if not)
   291тЖТ * - pm_code must be valid (C1-C5, OH)
   292тЖТ * - mileage_at_completion must be > 0 (discard zeros)
   293тЖТ * - Deduplicate by (train_number, pm_code, completion_date)
   294тЖТ */
   295тЖТexport function parsePmHistoryCsv(
   296тЖТ  csvContent: string,
   297тЖТ  fleetTrainNumbers?: Set<string>,
   298тЖТ  options: ImportOptions = {}
   299тЖТ): CsvParseResult<ImportedPMHistory> {
   300тЖТ  const result: CsvParseResult<ImportedPMHistory> = {
   301тЖТ    success: true,
   302тЖТ    data: [],
   303тЖТ    errors: [],
   304тЖТ    warnings: [],
   305тЖТ    stats: { totalRows: 0, validRows: 0, invalidRows: 0, duplicatesRemoved: 0 },
   306тЖТ  };
   307тЖТ
   308тЖТ  const parsed = Papa.parse<Record<string, string>>(csvContent, {
   309тЖТ    header: true,
   310тЖТ    skipEmptyLines: true,
   311тЖТ    transformHeader: (header) => header.trim().toLowerCase(),
   312тЖТ  });
   313тЖТ
   314тЖТ  if (parsed.errors.length > 0) {
   315тЖТ    for (const err of parsed.errors) {
   316тЖТ      result.errors.push({
   317тЖТ        row: err.row ?? 0,
   318тЖТ        field: 'csv',
   319тЖТ        message: err.message,
   320тЖТ      });
   321тЖТ    }
   322тЖТ    if (options.strict) {
   323тЖТ      result.success = false;
   324тЖТ      return result;
   325тЖТ    }
   326тЖТ  }
   327тЖТ
   328тЖТ  const seenKeys = new Set<string>();
   329тЖТ  result.stats.totalRows = parsed.data.length;
   330тЖТ
   331тЖТ  for (let i = 0; i < parsed.data.length; i++) {
   332тЖТ    const row = parsed.data[i];
   333тЖТ    const rowNum = i + 2;
   334тЖТ
   335тЖТ    // Extract fields directly per spec 009 column names
   336тЖТ    const trainNumber = (row['train_number'] ?? '').trim();
   337тЖТ    const pmCode = (row['pm_code'] ?? '').trim().toUpperCase();
   338тЖТ    const completionDateStr = (row['completion_date'] ?? '').trim();
   339тЖТ    // Handle both spec 009 name and lib/schemas name
   340тЖТ    const mileageStr = (row['mileage_at_completion'] ?? row['completion_mileage_km'] ?? '').trim();
   341тЖТ
   342тЖТ    const errors: ValidationError[] = [];
   343тЖТ
   344тЖТ    if (!trainNumber) {
   345тЖТ      errors.push({ field: 'train_number', message: 'Train number required' });
   346тЖТ    }
   347тЖТ
   348тЖТ    if (!pmCode) {
   349тЖТ      errors.push({ field: 'pm_code', message: 'PM code required' });
   350тЖТ    } else if (!VALID_PM_CODES.includes(pmCode)) {
   351тЖТ      errors.push({
   352тЖТ        field: 'pm_code',
   353тЖТ        message: `Invalid PM code '${pmCode}'. Must be one of: ${VALID_PM_CODES.join(', ')}`,
   354тЖТ      });
   355тЖТ    }
   356тЖТ
   357тЖТ    if (!isValidDateString(completionDateStr)) {
   358тЖТ      errors.push({ field: 'completion_date', message: 'Date must be in YYYY-MM-DD format' });
   359тЖТ    }
   360тЖТ
   361тЖТ    const mileageAtCompletion = mileageStr ? parseInt(mileageStr, 10) : 0;
   362тЖТ    if (mileageStr && isNaN(mileageAtCompletion)) {
   363тЖТ      errors.push({ field: 'mileage_at_completion', message: 'Mileage must be a number' });
   364тЖТ    }
   365тЖТ
   366тЖТ    if (errors.length > 0) {
   367тЖТ      result.stats.invalidRows++;
   368тЖТ      for (const err of errors) {
   369тЖТ        result.errors.push({
   370тЖТ          row: rowNum,
   371тЖТ          field: err.field,
   372тЖТ          message: err.message,
   373тЖТ          rawValue: String(row[err.field] ?? ''),
   374тЖТ        });
   375тЖТ      }
   376тЖТ      if (options.strict) {
   377тЖТ        result.success = false;
   378тЖТ        return result;
   379тЖТ      }
   380тЖТ      continue;
   381тЖТ    }
   382тЖТ
   383тЖТ    // Check if train exists in fleet (warning only)
   384тЖТ    if (fleetTrainNumbers && !fleetTrainNumbers.has(trainNumber)) {
   385тЖТ      result.warnings.push(
   386тЖТ        `Row ${rowNum}: Train '${trainNumber}' not found in fleet roster`
   387тЖТ      );
   388тЖТ    }
   389тЖТ
   390тЖТ    // Skip zero mileage entries per spec
   391тЖТ    if (mileageAtCompletion === 0 && mileageStr !== '') {
   392тЖТ      result.warnings.push(
   393тЖТ        `Row ${rowNum}: Skipping PM history with zero mileage for train '${trainNumber}'`
   394тЖТ      );
   395тЖТ      result.stats.duplicatesRemoved++;
   396тЖТ      continue;
   397тЖТ    }
   398тЖТ
   399тЖТ    // Deduplicate by (train_number, pm_code, completion_date)
   400тЖТ    const dedupeKey = `${trainNumber}|${pmCode}|${completionDateStr}`;
   401тЖТ    if (seenKeys.has(dedupeKey)) {
   402тЖТ      result.warnings.push(
   403тЖТ        `Row ${rowNum}: Duplicate entry for train '${trainNumber}' ${pmCode} on ${completionDateStr} - keeping first`
   404тЖТ      );
   405тЖТ      result.stats.duplicatesRemoved++;
   406тЖТ      continue;
   407тЖТ    }
   408тЖТ    seenKeys.add(dedupeKey);
   409тЖТ
   410тЖТ    result.data.push({
   411тЖТ      trainNumber,
   412тЖТ      pmCode,
   413тЖТ      completionDate: new Date(completionDateStr),
   414тЖТ      mileageAtCompletion,
   415тЖТ    });
   416тЖТ    result.stats.validRows++;
   417тЖТ  }
   418тЖТ
   419тЖТ  result.success = result.stats.invalidRows === 0 || !options.strict;
   420тЖТ  return result;
   421тЖТ}
   422тЖТ
   423тЖТ// =============================================================================
   424тЖТ// PM Rules CSV Parser
   425тЖТ// =============================================================================
   426тЖТ
   427тЖТ/**
   428тЖТ * Parse PM Rules CSV content (optional - defaults exist)
   429тЖТ *
   430тЖТ * Expected columns:
   431тЖТ * - fleet_code (required): Fleet type
   432тЖТ * - pm_code (required): PM type
   433тЖТ * - interval_km (required): Mileage trigger threshold
   434тЖТ * - interval_months (optional): Calendar trigger
   435тЖТ * - duration_days (required): Days train is out of service
   436тЖТ * - estimated_hours (required): Labor hours
   437тЖТ * - satisfies_codes (optional): Comma-separated lower PMs this satisfies
   438тЖТ */
   439тЖТexport function parsePmRulesCsv(
   440тЖТ  csvContent: string,
   441тЖТ  options: ImportOptions = {}
   442тЖТ): CsvParseResult<ImportedPMRule> {
   443тЖТ  const result: CsvParseResult<ImportedPMRule> = {
   444тЖТ    success: true,
   445тЖТ    data: [],
   446тЖТ    errors: [],
   447тЖТ    warnings: [],
   448тЖТ    stats: { totalRows: 0, validRows: 0, invalidRows: 0, duplicatesRemoved: 0 },
   449тЖТ  };
   450тЖТ
   451тЖТ  const parsed = Papa.parse<Record<string, string>>(csvContent, {
   452тЖТ    header: true,
   453тЖТ    skipEmptyLines: true,
   454тЖТ    transformHeader: (header) => header.trim().toLowerCase(),
   455тЖТ  });
   456тЖТ
   457тЖТ  if (parsed.errors.length > 0) {
   458тЖТ    for (const err of parsed.errors) {
   459тЖТ      result.errors.push({
   460тЖТ        row: err.row ?? 0,
   461тЖТ        field: 'csv',
   462тЖТ        message: err.message,
   463тЖТ      });
   464тЖТ    }
   465тЖТ    if (options.strict) {
   466тЖТ      result.success = false;
   467тЖТ      return result;
   468тЖТ    }
   469тЖТ  }
   470тЖТ
   471тЖТ  const seenKeys = new Set<string>();
   472тЖТ  result.stats.totalRows = parsed.data.length;
   473тЖТ
   474тЖТ  for (let i = 0; i < parsed.data.length; i++) {
   475тЖТ    const row = parsed.data[i];
   476тЖТ    const rowNum = i + 2;
   477тЖТ
   478тЖТ    const fleetCode = (row['fleet_code'] ?? '').trim().toUpperCase();
   479тЖТ    const pmCode = (row['pm_code'] ?? '').trim().toUpperCase();
   480тЖТ    const intervalKmStr = (row['interval_km'] ?? '').trim();
   481тЖТ    const intervalMonthsStr = (row['interval_months'] ?? '').trim();
   482тЖТ    const durationDaysStr = (row['duration_days'] ?? '').trim();
   483тЖТ    const estimatedHoursStr = (row['estimated_hours'] ?? '').trim();
   484тЖТ    const satisfiesCodesStr = (row['satisfies_codes'] ?? '').trim();
   485тЖТ
   486тЖТ    const errors: ValidationError[] = [];
   487тЖТ
   488тЖТ    if (!fleetCode) {
   489тЖТ      errors.push({ field: 'fleet_code', message: 'Fleet code required' });
   490тЖТ    }
   491тЖТ    if (!VALID_PM_CODES.includes(pmCode)) {
   492тЖТ      errors.push({
   493тЖТ        field: 'pm_code',
   494тЖТ        message: `Invalid PM code. Must be one of: ${VALID_PM_CODES.join(', ')}`,
   495тЖТ      });
   496тЖТ    }
   497тЖТ
   498тЖТ    const intervalKm = parseInt(intervalKmStr, 10);
   499тЖТ    if (isNaN(intervalKm) || intervalKm <= 0) {
   500тЖТ      errors.push({ field: 'interval_km', message: 'Interval km must be positive' });
   501тЖТ    }
   502тЖТ
   503тЖТ    const intervalMonths = intervalMonthsStr ? parseInt(intervalMonthsStr, 10) : null;
   504тЖТ    if (intervalMonthsStr && (isNaN(intervalMonths!) || intervalMonths! <= 0)) {
   505тЖТ      errors.push({ field: 'interval_months', message: 'Interval months must be positive' });
   506тЖТ    }
   507тЖТ
   508тЖТ    const durationDays = parseInt(durationDaysStr, 10);
   509тЖТ    if (isNaN(durationDays) || durationDays <= 0) {
   510тЖТ      errors.push({ field: 'duration_days', message: 'Duration days must be positive' });
   511тЖТ    }
   512тЖТ
   513тЖТ    const estimatedHours = parseInt(estimatedHoursStr, 10);
   514тЖТ    if (isNaN(estimatedHours) || estimatedHours <= 0) {
   515тЖТ      errors.push({ field: 'estimated_hours', message: 'Estimated hours must be positive' });
   516тЖТ    }
   517тЖТ
   518тЖТ    if (errors.length > 0) {
   519тЖТ      result.stats.invalidRows++;
   520тЖТ      for (const err of errors) {
   521тЖТ        result.errors.push({
   522тЖТ          row: rowNum,
   523тЖТ          field: err.field,
   524тЖТ          message: err.message,
   525тЖТ          rawValue: String(row[err.field] ?? ''),
   526тЖТ        });
   527тЖТ      }
   528тЖТ      if (options.strict) {
   529тЖТ        result.success = false;
   530тЖТ        return result;
   531тЖТ      }
   532тЖТ      continue;
   533тЖТ    }
   534тЖТ
   535тЖТ    // Deduplicate by (fleet_code, pm_code)
   536тЖТ    const dedupeKey = `${fleetCode}|${pmCode}`;
   537тЖТ    if (seenKeys.has(dedupeKey)) {
   538тЖТ      result.warnings.push(
   539тЖТ        `Row ${rowNum}: Duplicate rule for ${fleetCode} ${pmCode} - keeping first`
   540тЖТ      );
   541тЖТ      result.stats.duplicatesRemoved++;
   542тЖТ      continue;
   543тЖТ    }
   544тЖТ    seenKeys.add(dedupeKey);
   545тЖТ
   546тЖТ    // Parse satisfies_codes
   547тЖТ    const satisfiesCodes = satisfiesCodesStr
   548тЖТ      ? satisfiesCodesStr
   549тЖТ          .split(',')
   550тЖТ          .map((c) => c.trim().toUpperCase())
   551тЖТ          .filter((c) => VALID_PM_CODES.includes(c))
   552тЖТ      : [];
   553тЖТ
   554тЖТ    result.data.push({
   555тЖТ      fleetCode,
   556тЖТ      pmCode,
   557тЖТ      intervalKm,
   558тЖТ      intervalMonths,
   559тЖТ      durationDays,
   560тЖТ      estimatedHours,
   561тЖТ      satisfiesCodes,
   562тЖТ    });
   563тЖТ    result.stats.validRows++;
   564тЖТ  }
   565тЖТ
   566тЖТ  result.success = result.stats.invalidRows === 0 || !options.strict;
   567тЖТ  return result;
   568тЖТ}
   569тЖТ
   570тЖТ// =============================================================================
   571тЖТ// High-Level Import Function
   572тЖТ// =============================================================================
   573тЖТ
   574тЖТ/** Input for complete demo data import */
   575тЖТexport interface DemoImportInput {
   576тЖТ  fleetRoster: string;
   577тЖТ  pmHistory: string;
   578тЖТ  pmRules?: string;
   579тЖТ}
   580тЖТ
   581тЖТ/** Result of complete demo data import */
   582тЖТexport interface DemoImportResult {
   583тЖТ  success: boolean;
   584тЖТ  fleetState: FleetState | null;
   585тЖТ  errors: CsvParseError[];
   586тЖТ  warnings: string[];
   587тЖТ  stats: {
   588тЖТ    trains: { valid: number; invalid: number };
   589тЖТ    pmHistory: { valid: number; invalid: number };
   590тЖТ    pmRules: { valid: number; invalid: number };
   591тЖТ  };
   592тЖТ}
   593тЖТ
   594тЖТ/**
   595тЖТ * Import complete demo data from CSV strings
   596тЖТ *
   597тЖТ * This is the main entry point for the demo CSV import feature.
   598тЖТ * Parses Fleet Roster and PM History CSVs, optionally PM Rules.
   599тЖТ *
   600тЖТ * After import, calculates estimated daily km for each train based on PM history.
   601тЖТ */
   602тЖТexport function importDemoData(
   603тЖТ  input: DemoImportInput,
   604тЖТ  options: ImportOptions = {}
   605тЖТ): DemoImportResult {
   606тЖТ  const result: DemoImportResult = {
   607тЖТ    success: true,
   608тЖТ    fleetState: null,
   609тЖТ    errors: [],
   610тЖТ    warnings: [],
   611тЖТ    stats: {
   612тЖТ      trains: { valid: 0, invalid: 0 },
   613тЖТ      pmHistory: { valid: 0, invalid: 0 },
   614тЖТ      pmRules: { valid: 0, invalid: 0 },
   615тЖТ    },
   616тЖТ  };
   617тЖТ
   618тЖТ  // 1. Parse Fleet Roster
   619тЖТ  const rosterResult = parseFleetRosterCsv(input.fleetRoster, options);
   620тЖТ  result.errors.push(...rosterResult.errors);
   621тЖТ  result.warnings.push(...rosterResult.warnings);
   622тЖТ  result.stats.trains = {
   623тЖТ    valid: rosterResult.stats.validRows,
   624тЖТ    invalid: rosterResult.stats.invalidRows,
   625тЖТ  };
   626тЖТ
   627тЖТ  if (rosterResult.data.length === 0) {
   628тЖТ    result.success = false;
   629тЖТ    result.errors.push({
   630тЖТ      row: 0,
   631тЖТ      field: 'fleetRoster',
   632тЖТ      message: 'No valid trains found in fleet roster CSV',
   633тЖТ    });
   634тЖТ    return result;
   635тЖТ  }
   636тЖТ
   637тЖТ  // Build set of train numbers for PM history validation
   638тЖТ  const trainNumbers = new Set(rosterResult.data.map((t) => t.trainNumber));
   639тЖТ
   640тЖТ  // 2. Parse PM History
   641тЖТ  const historyResult = parsePmHistoryCsv(input.pmHistory, trainNumbers, options);
   642тЖТ  result.errors.push(...historyResult.errors);
   643тЖТ  result.warnings.push(...historyResult.warnings);
   644тЖТ  result.stats.pmHistory = {
   645тЖТ    valid: historyResult.stats.validRows,
   646тЖТ    invalid: historyResult.stats.invalidRows,
   647тЖТ  };
   648тЖТ
   649тЖТ  // 3. Parse PM Rules (or use defaults)
   650тЖТ  let pmRules: ImportedPMRule[];
   651тЖТ
   652тЖТ  if (input.pmRules) {
   653тЖТ    const rulesResult = parsePmRulesCsv(input.pmRules, options);
   654тЖТ    result.errors.push(...rulesResult.errors);
   655тЖТ    result.warnings.push(...rulesResult.warnings);
   656тЖТ    result.stats.pmRules = {
   657тЖТ      valid: rulesResult.stats.validRows,
   658тЖТ      invalid: rulesResult.stats.invalidRows,
   659тЖТ    };
   660тЖТ    pmRules = rulesResult.data;
   661тЖТ  } else {
   662тЖТ    // Use default PM rules from data.ts
   663тЖТ    pmRules = getDefaultPMRules(rosterResult.data);
   664тЖТ    result.warnings.push('Using default PM rules (no pm_rules CSV provided)');
   665тЖТ    result.stats.pmRules = { valid: pmRules.length, invalid: 0 };
   666тЖТ  }
   667тЖТ
   668тЖТ  // 4. Calculate daily km estimates from PM history
   669тЖТ  const trains = calculateDailyEstimates(rosterResult.data, historyResult.data);
   670тЖТ
   671тЖТ  // 5. Assemble fleet state
   672тЖТ  result.fleetState = {
   673тЖТ    trains,
   674тЖТ    pmHistory: historyResult.data,
   675тЖТ    pmRules,
   676тЖТ  };
   677тЖТ
   678тЖТ  result.success = result.errors.length === 0 || !options.strict;
   679тЖТ  return result;
   680тЖТ}
   681тЖТ
   682тЖТ// =============================================================================
   683тЖТ// Helper Functions
   684тЖТ// =============================================================================
   685тЖТ
   686тЖТ/**
   687тЖТ * Default PM rules for unknown fleet types per spec 009
   688тЖТ * Uses KS (Kawasaki-style) intervals as baseline
   689тЖТ */
   690тЖТconst DEFAULT_PM_RULES: Omit<ImportedPMRule, 'fleetCode'>[] = [
   691тЖТ  { pmCode: 'C1', intervalKm: 12500, intervalMonths: 6, durationDays: 1, estimatedHours: 8, satisfiesCodes: [] },
   692тЖТ  { pmCode: 'C2', intervalKm: 50000, intervalMonths: 24, durationDays: 3, estimatedHours: 24, satisfiesCodes: ['C1'] },
   693тЖТ  { pmCode: 'C3', intervalKm: 100000, intervalMonths: 48, durationDays: 7, estimatedHours: 72, satisfiesCodes: ['C1', 'C2'] },
   694тЖТ  { pmCode: 'C4', intervalKm: 200000, intervalMonths: 96, durationDays: 14, estimatedHours: 160, satisfiesCodes: ['C1', 'C2', 'C3'] },
   695тЖТ  { pmCode: 'C5', intervalKm: 400000, intervalMonths: null, durationDays: 21, estimatedHours: 240, satisfiesCodes: ['C1', 'C2', 'C3', 'C4'] },
   696тЖТ  { pmCode: 'OH', intervalKm: 800000, intervalMonths: null, durationDays: 45, estimatedHours: 500, satisfiesCodes: ['C1', 'C2', 'C3', 'C4', 'C5'] },
   697тЖТ];
   698тЖТ
   699тЖТ/**
   700тЖТ * Get default PM rules for the fleets in the roster
   701тЖТ *
   702тЖТ * Uses PM_RULES_BY_FLEET for known fleet codes (ML, AEL, TCL),
   703тЖТ * falls back to DEFAULT_PM_RULES for unknown fleet codes.
   704тЖТ */
   705тЖТfunction getDefaultPMRules(trains: ImportedTrain[]): ImportedPMRule[] {
   706тЖТ  const fleetCodes = new Set(trains.map((t) => t.fleetCode));
   707тЖТ  const rules: ImportedPMRule[] = [];
   708тЖТ
   709тЖТ  for (const fleetCode of fleetCodes) {
   710тЖТ    const fleetRules = PM_RULES_BY_FLEET[fleetCode];
   711тЖТ    if (fleetRules) {
   712тЖТ      for (const rule of fleetRules) {
   713тЖТ        rules.push({
   714тЖТ          fleetCode,
   715тЖТ          pmCode: rule.pmCode,
   716тЖТ          intervalKm: rule.intervalKm,
   717тЖТ          intervalMonths: rule.intervalMonths || null,
   718тЖТ          durationDays: Math.ceil(rule.estimatedHours / 8), // Assume 8h workday
   719тЖТ          estimatedHours: rule.estimatedHours,
   720тЖТ          satisfiesCodes: rule.satisfiesCodes ?? [],
   721тЖТ        });
   722тЖТ      }
   723тЖТ    } else {
   724тЖТ      // Use default rules for unknown fleet codes
   725тЖТ      for (const rule of DEFAULT_PM_RULES) {
   726тЖТ        rules.push({
   727тЖТ          fleetCode,
   728тЖТ          ...rule,
   729тЖТ        });
   730тЖТ      }
   731тЖТ    }
   732тЖТ  }
   733тЖТ
   734тЖТ  return rules;
   735тЖТ}
   736тЖТ
   737тЖТ/**
   738тЖТ * Calculate daily km estimates for each train based on PM history
   739тЖТ *
   740тЖТ * Uses recent velocity between last 2 PMs if available,
   741тЖТ * falls back to lifetime average from commissioning.
   742тЖТ *
   743тЖТ * @see specs/009-demo-application.md Section 9.3.1 calculateDailyUtilization
   744тЖТ */
   745тЖТfunction calculateDailyEstimates(
   746тЖТ  trains: ImportedTrain[],
   747тЖТ  pmHistory: ImportedPMHistory[]
   748тЖТ): ImportedTrain[] {
   749тЖТ  // Group PM history by train
   750тЖТ  const historyByTrain = new Map<string, ImportedPMHistory[]>();
   751тЖТ  for (const pm of pmHistory) {
   752тЖТ    const existing = historyByTrain.get(pm.trainNumber) ?? [];
   753тЖТ    existing.push(pm);
   754тЖТ    historyByTrain.set(pm.trainNumber, existing);
   755тЖТ  }
   756тЖТ
   757тЖТ  return trains.map((train) => {
   758тЖТ    const history = historyByTrain.get(train.trainNumber) ?? [];
   759тЖТ
   760тЖТ    // Filter valid entries and sort by completion date desc
   761тЖТ    const validHistory = history
   762тЖТ      .filter((h) => h.mileageAtCompletion > 0)
   763тЖТ      .sort((a, b) => b.completionDate.getTime() - a.completionDate.getTime());
   764тЖТ
   765тЖТ    // Try recent velocity between last 2 PMs
   766тЖТ    if (validHistory.length >= 2) {
   767тЖТ      const recent = validHistory[0];
   768тЖТ      const previous = validHistory[1];
   769тЖТ      const daysBetween = Math.floor(
   770тЖТ        (recent.completionDate.getTime() - previous.completionDate.getTime()) /
   771тЖТ          (1000 * 60 * 60 * 24)
   772тЖТ      );
   773тЖТ      const kmBetween = recent.mileageAtCompletion - previous.mileageAtCompletion;
   774тЖТ
   775тЖТ      // Sanity checks: at least 14 days between and positive km
   776тЖТ      if (daysBetween >= 14 && kmBetween > 0) {
   777тЖТ        const rate = kmBetween / daysBetween;
   778тЖТ        // Typical metro range: 50-500 km/day
   779тЖТ        if (rate > 50 && rate < 500) {
   780тЖТ          return {
   781тЖТ            ...train,
   782тЖТ            estimatedDailyKm: Math.round(rate),
   783тЖТ            confidence: 'HISTORICAL' as const,
   784тЖТ          };
   785тЖТ        }
   786тЖТ      }
   787тЖТ    }
   788тЖТ
   789тЖТ    // Fallback: lifetime average from commissioning
   790тЖТ    const daysSinceCommission = Math.floor(
   791тЖТ      (Date.now() - train.commissioningDate.getTime()) / (1000 * 60 * 60 * 24)
   792тЖТ    );
   793тЖТ    if (daysSinceCommission > 0 && train.currentMileageKm > 0) {
   794тЖТ      const rate = train.currentMileageKm / daysSinceCommission;
   795тЖТ      if (rate > 0 && rate < 1000) {
   796тЖТ        return {
   797тЖТ          ...train,
   798тЖТ          estimatedDailyKm: Math.round(rate),
   799тЖТ          confidence: 'HISTORICAL' as const,
   800тЖТ        };
   801тЖТ      }
   802тЖТ    }
   803тЖТ
   804тЖТ    // Last resort: keep default
   805тЖТ    return train;
   806тЖТ  });
   807тЖТ}
   808тЖТ
   809тЖТ

