/**
 * MMS Demo CSV Import Module
 *
 * Parses client-provided CSV files (Maximo exports) for the demo application.
 * Supports Fleet Roster, PM History, and PM Rules CSVs per spec 009 Section 9.2.1.
 *
 * @example
 * ```typescript
 * import { parseFleetRosterCsv, parsePmHistoryCsv, importDemoData } from './csv-import';
 *
 * // Parse individual CSV strings
 * const roster = parseFleetRosterCsv(csvContent);
 * const history = parsePmHistoryCsv(csvContent);
 *
 * // Import complete demo data from multiple CSVs
 * const demoData = importDemoData({
 *   fleetRoster: rosterCsv,
 *   pmHistory: historyCsv,
 *   pmRules: rulesCsv, // optional, uses defaults if not provided
 * });
 * ```
 *
 * @see specs/009-demo-application.md Section 9.2.1
 */

import * as Papa from 'papaparse';
import {
  parseFleetRosterCsvRow,
  isValidDateString,
  type ValidationError,
} from '../lib/schemas';
import { PM_RULES_BY_FLEET } from './data';

// =============================================================================
// Types
// =============================================================================

/** Imported train from Fleet Roster CSV */
export interface ImportedTrain {
  trainNumber: string;
  fleetCode: string;
  currentMileageKm: number;
  commissioningDate: Date;
  estimatedDailyKm: number;
  confidence: 'HISTORICAL' | 'ESTIMATED';
}

/** Imported PM history record */
export interface ImportedPMHistory {
  trainNumber: string;
  pmCode: string;
  completionDate: Date;
  mileageAtCompletion: number;
}

/** Imported PM rule */
export interface ImportedPMRule {
  fleetCode: string;
  pmCode: string;
  intervalKm: number;
  intervalMonths: number | null;
  durationDays: number;
  estimatedHours: number;
  satisfiesCodes: string[];
}

/** Complete fleet state from imported data */
export interface FleetState {
  trains: ImportedTrain[];
  pmHistory: ImportedPMHistory[];
  pmRules: ImportedPMRule[];
}

/** CSV parse result with detailed errors */
export interface CsvParseResult<T> {
  success: boolean;
  data: T[];
  errors: CsvParseError[];
  warnings: string[];
  stats: {
    totalRows: number;
    validRows: number;
    invalidRows: number;
    duplicatesRemoved: number;
  };
}

/** Detailed parse error with row information */
export interface CsvParseError {
  row: number;
  field: string;
  message: string;
  rawValue?: string;
}

/** Import options for customizing behavior */
export interface ImportOptions {
  /** Throw on first error (default: false, collect all errors) */
  strict?: boolean;
  /** Default commissioning date if not provided (default: 5 years ago) */
  defaultCommissioningDate?: Date;
  /** Daily km estimate if no PM history exists (default: 150 km/day) */
  defaultDailyKm?: number;
}

// =============================================================================
// Constants
// =============================================================================

/** Default daily km for trains without history */
const DEFAULT_DAILY_KM = 150;

/** Minimum commissioning date (sanity check) */
const MIN_COMMISSIONING_DATE = new Date('2000-01-01');

/** Valid PM codes per spec */
const VALID_PM_CODES = ['C1', 'C2', 'C3', 'C4', 'C5', 'OH'];

// =============================================================================
// Fleet Roster CSV Parser
// =============================================================================

/**
 * Parse Fleet Roster CSV content
 *
 * Expected columns:
 * - train_number (required): Unique train identifier
 * - fleet_code (required): Fleet type (e.g., "KS", "ALSTOM")
 * - current_mileage_km (required): Current odometer reading
 * - commissioning_date (optional): YYYY-MM-DD format
 *
 * Validation rules per spec 009:
 * - train_number must be unique
 * - current_mileage_km must be > 0
 * - commissioning_date must be in the past
 */
export function parseFleetRosterCsv(
  csvContent: string,
  options: ImportOptions = {}
): CsvParseResult<ImportedTrain> {
  const result: CsvParseResult<ImportedTrain> = {
    success: true,
    data: [],
    errors: [],
    warnings: [],
    stats: { totalRows: 0, validRows: 0, invalidRows: 0, duplicatesRemoved: 0 },
  };

  const defaultDate =
    options.defaultCommissioningDate ??
    new Date(Date.now() - 5 * 365 * 24 * 60 * 60 * 1000); // 5 years ago

  const parsed = Papa.parse<Record<string, string>>(csvContent, {
    header: true,
    skipEmptyLines: true,
    transformHeader: (header) => header.trim().toLowerCase(),
  });

  if (parsed.errors.length > 0) {
    for (const err of parsed.errors) {
      result.errors.push({
        row: err.row ?? 0,
        field: 'csv',
        message: err.message,
      });
    }
    if (options.strict) {
      result.success = false;
      return result;
    }
  }

  const seenTrainNumbers = new Set<string>();
  result.stats.totalRows = parsed.data.length;

  for (let i = 0; i < parsed.data.length; i++) {
    const row = parsed.data[i];
    const rowNum = i + 2; // +2 for header row and 0-based index

    const parseResult = parseFleetRosterCsvRow(row);

    if (!parseResult.success) {
      result.stats.invalidRows++;
      for (const err of parseResult.errors) {
        result.errors.push({
          row: rowNum,
          field: err.field,
          message: err.message,
          rawValue: String(row[err.field] ?? ''),
        });
      }
      if (options.strict) {
        result.success = false;
        return result;
      }
      continue;
    }

    const data = parseResult.data;

    // Check for duplicate train numbers
    if (seenTrainNumbers.has(data.trainNumber)) {
      result.warnings.push(
        `Row ${rowNum}: Duplicate train number '${data.trainNumber}' - keeping first occurrence`
      );
      result.stats.duplicatesRemoved++;
      continue;
    }
    seenTrainNumbers.add(data.trainNumber);

    // Validate mileage > 0
    if (data.currentMileageKm <= 0) {
      result.errors.push({
        row: rowNum,
        field: 'current_mileage_km',
        message: 'Mileage must be greater than 0',
        rawValue: String(data.currentMileageKm),
      });
      result.stats.invalidRows++;
      if (options.strict) {
        result.success = false;
        return result;
      }
      continue;
    }

    // Parse commissioning date
    let commissioningDate: Date;
    if (data.commissioningDate && isValidDateString(data.commissioningDate)) {
      commissioningDate = new Date(data.commissioningDate);

      // Validate commissioning date is in the past
      if (commissioningDate > new Date()) {
        result.errors.push({
          row: rowNum,
          field: 'commissioning_date',
          message: 'Commissioning date must be in the past',
          rawValue: data.commissioningDate,
        });
        result.stats.invalidRows++;
        if (options.strict) {
          result.success = false;
          return result;
        }
        continue;
      }

      // Sanity check: not before 2000
      if (commissioningDate < MIN_COMMISSIONING_DATE) {
        result.warnings.push(
          `Row ${rowNum}: Unusually early commissioning date '${data.commissioningDate}'`
        );
      }
    } else {
      commissioningDate = defaultDate;
      result.warnings.push(
        `Row ${rowNum}: Missing commissioning date, using default (${defaultDate.toISOString().split('T')[0]})`
      );
    }

    result.data.push({
      trainNumber: data.trainNumber,
      fleetCode: data.fleetCode.toUpperCase(),
      currentMileageKm: data.currentMileageKm,
      commissioningDate,
      estimatedDailyKm: options.defaultDailyKm ?? DEFAULT_DAILY_KM,
      confidence: 'ESTIMATED',
    });
    result.stats.validRows++;
  }

  result.success = result.stats.invalidRows === 0 || !options.strict;
  return result;
}

// =============================================================================
// PM History CSV Parser
// =============================================================================

/**
 * Parse PM History CSV content
 *
 * Expected columns (per spec 009):
 * - train_number (required): References fleet roster
 * - pm_code (required): PM type (C1, C2, C3, C4, C5, OH)
 * - completion_date (required): YYYY-MM-DD format
 * - mileage_at_completion (optional but recommended): Odometer at completion
 *
 * Validation rules per spec 009:
 * - train_number should exist in fleet roster (warning if not)
 * - pm_code must be valid (C1-C5, OH)
 * - mileage_at_completion must be > 0 (discard zeros)
 * - Deduplicate by (train_number, pm_code, completion_date)
 */
export function parsePmHistoryCsv(
  csvContent: string,
  fleetTrainNumbers?: Set<string>,
  options: ImportOptions = {}
): CsvParseResult<ImportedPMHistory> {
  const result: CsvParseResult<ImportedPMHistory> = {
    success: true,
    data: [],
    errors: [],
    warnings: [],
    stats: { totalRows: 0, validRows: 0, invalidRows: 0, duplicatesRemoved: 0 },
  };

  const parsed = Papa.parse<Record<string, string>>(csvContent, {
    header: true,
    skipEmptyLines: true,
    transformHeader: (header) => header.trim().toLowerCase(),
  });

  if (parsed.errors.length > 0) {
    for (const err of parsed.errors) {
      result.errors.push({
        row: err.row ?? 0,
        field: 'csv',
        message: err.message,
      });
    }
    if (options.strict) {
      result.success = false;
      return result;
    }
  }

  const seenKeys = new Set<string>();
  result.stats.totalRows = parsed.data.length;

  for (let i = 0; i < parsed.data.length; i++) {
    const row = parsed.data[i];
    const rowNum = i + 2;

    // Extract fields directly per spec 009 column names
    const trainNumber = (row['train_number'] ?? '').trim();
    const pmCode = (row['pm_code'] ?? '').trim().toUpperCase();
    const completionDateStr = (row['completion_date'] ?? '').trim();
    // Handle both spec 009 name and lib/schemas name
    const mileageStr = (row['mileage_at_completion'] ?? row['completion_mileage_km'] ?? '').trim();

    const errors: ValidationError[] = [];

    if (!trainNumber) {
      errors.push({ field: 'train_number', message: 'Train number required' });
    }

    if (!pmCode) {
      errors.push({ field: 'pm_code', message: 'PM code required' });
    } else if (!VALID_PM_CODES.includes(pmCode)) {
      errors.push({
        field: 'pm_code',
        message: `Invalid PM code '${pmCode}'. Must be one of: ${VALID_PM_CODES.join(', ')}`,
      });
    }

    if (!isValidDateString(completionDateStr)) {
      errors.push({ field: 'completion_date', message: 'Date must be in YYYY-MM-DD format' });
    }

    const mileageAtCompletion = mileageStr ? parseInt(mileageStr, 10) : 0;
    if (mileageStr && isNaN(mileageAtCompletion)) {
      errors.push({ field: 'mileage_at_completion', message: 'Mileage must be a number' });
    }

    if (errors.length > 0) {
      result.stats.invalidRows++;
      for (const err of errors) {
        result.errors.push({
          row: rowNum,
          field: err.field,
          message: err.message,
          rawValue: String(row[err.field] ?? ''),
        });
      }
      if (options.strict) {
        result.success = false;
        return result;
      }
      continue;
    }

    // Check if train exists in fleet (warning only)
    if (fleetTrainNumbers && !fleetTrainNumbers.has(trainNumber)) {
      result.warnings.push(
        `Row ${rowNum}: Train '${trainNumber}' not found in fleet roster`
      );
    }

    // Skip zero mileage entries per spec
    if (mileageAtCompletion === 0 && mileageStr !== '') {
      result.warnings.push(
        `Row ${rowNum}: Skipping PM history with zero mileage for train '${trainNumber}'`
      );
      result.stats.duplicatesRemoved++;
      continue;
    }

    // Deduplicate by (train_number, pm_code, completion_date)
    const dedupeKey = `${trainNumber}|${pmCode}|${completionDateStr}`;
    if (seenKeys.has(dedupeKey)) {
      result.warnings.push(
        `Row ${rowNum}: Duplicate entry for train '${trainNumber}' ${pmCode} on ${completionDateStr} - keeping first`
      );
      result.stats.duplicatesRemoved++;
      continue;
    }
    seenKeys.add(dedupeKey);

    result.data.push({
      trainNumber,
      pmCode,
      completionDate: new Date(completionDateStr),
      mileageAtCompletion,
    });
    result.stats.validRows++;
  }

  result.success = result.stats.invalidRows === 0 || !options.strict;
  return result;
}

// =============================================================================
// PM Rules CSV Parser
// =============================================================================

/**
 * Parse PM Rules CSV content (optional - defaults exist)
 *
 * Expected columns:
 * - fleet_code (required): Fleet type
 * - pm_code (required): PM type
 * - interval_km (required): Mileage trigger threshold
 * - interval_months (optional): Calendar trigger
 * - duration_days (required): Days train is out of service
 * - estimated_hours (required): Labor hours
 * - satisfies_codes (optional): Comma-separated lower PMs this satisfies
 */
export function parsePmRulesCsv(
  csvContent: string,
  options: ImportOptions = {}
): CsvParseResult<ImportedPMRule> {
  const result: CsvParseResult<ImportedPMRule> = {
    success: true,
    data: [],
    errors: [],
    warnings: [],
    stats: { totalRows: 0, validRows: 0, invalidRows: 0, duplicatesRemoved: 0 },
  };

  const parsed = Papa.parse<Record<string, string>>(csvContent, {
    header: true,
    skipEmptyLines: true,
    transformHeader: (header) => header.trim().toLowerCase(),
  });

  if (parsed.errors.length > 0) {
    for (const err of parsed.errors) {
      result.errors.push({
        row: err.row ?? 0,
        field: 'csv',
        message: err.message,
      });
    }
    if (options.strict) {
      result.success = false;
      return result;
    }
  }

  const seenKeys = new Set<string>();
  result.stats.totalRows = parsed.data.length;

  for (let i = 0; i < parsed.data.length; i++) {
    const row = parsed.data[i];
    const rowNum = i + 2;

    const fleetCode = (row['fleet_code'] ?? '').trim().toUpperCase();
    const pmCode = (row['pm_code'] ?? '').trim().toUpperCase();
    const intervalKmStr = (row['interval_km'] ?? '').trim();
    const intervalMonthsStr = (row['interval_months'] ?? '').trim();
    const durationDaysStr = (row['duration_days'] ?? '').trim();
    const estimatedHoursStr = (row['estimated_hours'] ?? '').trim();
    const satisfiesCodesStr = (row['satisfies_codes'] ?? '').trim();

    const errors: ValidationError[] = [];

    if (!fleetCode) {
      errors.push({ field: 'fleet_code', message: 'Fleet code required' });
    }
    if (!VALID_PM_CODES.includes(pmCode)) {
      errors.push({
        field: 'pm_code',
        message: `Invalid PM code. Must be one of: ${VALID_PM_CODES.join(', ')}`,
      });
    }

    const intervalKm = parseInt(intervalKmStr, 10);
    if (isNaN(intervalKm) || intervalKm <= 0) {
      errors.push({ field: 'interval_km', message: 'Interval km must be positive' });
    }

    const intervalMonths = intervalMonthsStr ? parseInt(intervalMonthsStr, 10) : null;
    if (intervalMonthsStr && (isNaN(intervalMonths!) || intervalMonths! <= 0)) {
      errors.push({ field: 'interval_months', message: 'Interval months must be positive' });
    }

    const durationDays = parseInt(durationDaysStr, 10);
    if (isNaN(durationDays) || durationDays <= 0) {
      errors.push({ field: 'duration_days', message: 'Duration days must be positive' });
    }

    const estimatedHours = parseInt(estimatedHoursStr, 10);
    if (isNaN(estimatedHours) || estimatedHours <= 0) {
      errors.push({ field: 'estimated_hours', message: 'Estimated hours must be positive' });
    }

    if (errors.length > 0) {
      result.stats.invalidRows++;
      for (const err of errors) {
        result.errors.push({
          row: rowNum,
          field: err.field,
          message: err.message,
          rawValue: String(row[err.field] ?? ''),
        });
      }
      if (options.strict) {
        result.success = false;
        return result;
      }
      continue;
    }

    // Deduplicate by (fleet_code, pm_code)
    const dedupeKey = `${fleetCode}|${pmCode}`;
    if (seenKeys.has(dedupeKey)) {
      result.warnings.push(
        `Row ${rowNum}: Duplicate rule for ${fleetCode} ${pmCode} - keeping first`
      );
      result.stats.duplicatesRemoved++;
      continue;
    }
    seenKeys.add(dedupeKey);

    // Parse satisfies_codes
    const satisfiesCodes = satisfiesCodesStr
      ? satisfiesCodesStr
          .split(',')
          .map((c) => c.trim().toUpperCase())
          .filter((c) => VALID_PM_CODES.includes(c))
      : [];

    result.data.push({
      fleetCode,
      pmCode,
      intervalKm,
      intervalMonths,
      durationDays,
      estimatedHours,
      satisfiesCodes,
    });
    result.stats.validRows++;
  }

  result.success = result.stats.invalidRows === 0 || !options.strict;
  return result;
}

// =============================================================================
// High-Level Import Function
// =============================================================================

/** Input for complete demo data import */
export interface DemoImportInput {
  fleetRoster: string;
  pmHistory: string;
  pmRules?: string;
}

/** Result of complete demo data import */
export interface DemoImportResult {
  success: boolean;
  fleetState: FleetState | null;
  errors: CsvParseError[];
  warnings: string[];
  stats: {
    trains: { valid: number; invalid: number };
    pmHistory: { valid: number; invalid: number };
    pmRules: { valid: number; invalid: number };
  };
}

/**
 * Import complete demo data from CSV strings
 *
 * This is the main entry point for the demo CSV import feature.
 * Parses Fleet Roster and PM History CSVs, optionally PM Rules.
 *
 * After import, calculates estimated daily km for each train based on PM history.
 */
export function importDemoData(
  input: DemoImportInput,
  options: ImportOptions = {}
): DemoImportResult {
  const result: DemoImportResult = {
    success: true,
    fleetState: null,
    errors: [],
    warnings: [],
    stats: {
      trains: { valid: 0, invalid: 0 },
      pmHistory: { valid: 0, invalid: 0 },
      pmRules: { valid: 0, invalid: 0 },
    },
  };

  // 1. Parse Fleet Roster
  const rosterResult = parseFleetRosterCsv(input.fleetRoster, options);
  result.errors.push(...rosterResult.errors);
  result.warnings.push(...rosterResult.warnings);
  result.stats.trains = {
    valid: rosterResult.stats.validRows,
    invalid: rosterResult.stats.invalidRows,
  };

  if (rosterResult.data.length === 0) {
    result.success = false;
    result.errors.push({
      row: 0,
      field: 'fleetRoster',
      message: 'No valid trains found in fleet roster CSV',
    });
    return result;
  }

  // Build set of train numbers for PM history validation
  const trainNumbers = new Set(rosterResult.data.map((t) => t.trainNumber));

  // 2. Parse PM History
  const historyResult = parsePmHistoryCsv(input.pmHistory, trainNumbers, options);
  result.errors.push(...historyResult.errors);
  result.warnings.push(...historyResult.warnings);
  result.stats.pmHistory = {
    valid: historyResult.stats.validRows,
    invalid: historyResult.stats.invalidRows,
  };

  // 3. Parse PM Rules (or use defaults)
  let pmRules: ImportedPMRule[];

  if (input.pmRules) {
    const rulesResult = parsePmRulesCsv(input.pmRules, options);
    result.errors.push(...rulesResult.errors);
    result.warnings.push(...rulesResult.warnings);
    result.stats.pmRules = {
      valid: rulesResult.stats.validRows,
      invalid: rulesResult.stats.invalidRows,
    };
    pmRules = rulesResult.data;
  } else {
    // Use default PM rules from data.ts
    pmRules = getDefaultPMRules(rosterResult.data);
    result.warnings.push('Using default PM rules (no pm_rules CSV provided)');
    result.stats.pmRules = { valid: pmRules.length, invalid: 0 };
  }

  // 4. Calculate daily km estimates from PM history
  const trains = calculateDailyEstimates(rosterResult.data, historyResult.data);

  // 5. Assemble fleet state
  result.fleetState = {
    trains,
    pmHistory: historyResult.data,
    pmRules,
  };

  result.success = result.errors.length === 0 || !options.strict;
  return result;
}

// =============================================================================
// Helper Functions
// =============================================================================

/**
 * Default PM rules for unknown fleet types per spec 009
 * Uses KS (Kawasaki-style) intervals as baseline
 */
const DEFAULT_PM_RULES: Omit<ImportedPMRule, 'fleetCode'>[] = [
  { pmCode: 'C1', intervalKm: 12500, intervalMonths: 6, durationDays: 1, estimatedHours: 8, satisfiesCodes: [] },
  { pmCode: 'C2', intervalKm: 50000, intervalMonths: 24, durationDays: 3, estimatedHours: 24, satisfiesCodes: ['C1'] },
  { pmCode: 'C3', intervalKm: 100000, intervalMonths: 48, durationDays: 7, estimatedHours: 72, satisfiesCodes: ['C1', 'C2'] },
  { pmCode: 'C4', intervalKm: 200000, intervalMonths: 96, durationDays: 14, estimatedHours: 160, satisfiesCodes: ['C1', 'C2', 'C3'] },
  { pmCode: 'C5', intervalKm: 400000, intervalMonths: null, durationDays: 21, estimatedHours: 240, satisfiesCodes: ['C1', 'C2', 'C3', 'C4'] },
  { pmCode: 'OH', intervalKm: 800000, intervalMonths: null, durationDays: 45, estimatedHours: 500, satisfiesCodes: ['C1', 'C2', 'C3', 'C4', 'C5'] },
];

/**
 * Get default PM rules for the fleets in the roster
 *
 * Uses PM_RULES_BY_FLEET for known fleet codes (ML, AEL, TCL),
 * falls back to DEFAULT_PM_RULES for unknown fleet codes.
 */
function getDefaultPMRules(trains: ImportedTrain[]): ImportedPMRule[] {
  const fleetCodes = new Set(trains.map((t) => t.fleetCode));
  const rules: ImportedPMRule[] = [];

  for (const fleetCode of fleetCodes) {
    const fleetRules = PM_RULES_BY_FLEET[fleetCode];
    if (fleetRules) {
      for (const rule of fleetRules) {
        rules.push({
          fleetCode,
          pmCode: rule.pmCode,
          intervalKm: rule.intervalKm,
          intervalMonths: rule.intervalMonths || null,
          durationDays: Math.ceil(rule.estimatedHours / 8), // Assume 8h workday
          estimatedHours: rule.estimatedHours,
          satisfiesCodes: rule.satisfiesCodes ?? [],
        });
      }
    } else {
      // Use default rules for unknown fleet codes
      for (const rule of DEFAULT_PM_RULES) {
        rules.push({
          fleetCode,
          ...rule,
        });
      }
    }
  }

  return rules;
}

/**
 * Calculate daily km estimates for each train based on PM history
 *
 * Uses recent velocity between last 2 PMs if available,
 * falls back to lifetime average from commissioning.
 *
 * @see specs/009-demo-application.md Section 9.3.1 calculateDailyUtilization
 */
function calculateDailyEstimates(
  trains: ImportedTrain[],
  pmHistory: ImportedPMHistory[]
): ImportedTrain[] {
  // Group PM history by train
  const historyByTrain = new Map<string, ImportedPMHistory[]>();
  for (const pm of pmHistory) {
    const existing = historyByTrain.get(pm.trainNumber) ?? [];
    existing.push(pm);
    historyByTrain.set(pm.trainNumber, existing);
  }

  return trains.map((train) => {
    const history = historyByTrain.get(train.trainNumber) ?? [];

    // Filter valid entries and sort by completion date desc
    const validHistory = history
      .filter((h) => h.mileageAtCompletion > 0)
      .sort((a, b) => b.completionDate.getTime() - a.completionDate.getTime());

    // Try recent velocity between last 2 PMs
    if (validHistory.length >= 2) {
      const recent = validHistory[0];
      const previous = validHistory[1];
      const daysBetween = Math.floor(
        (recent.completionDate.getTime() - previous.completionDate.getTime()) /
          (1000 * 60 * 60 * 24)
      );
      const kmBetween = recent.mileageAtCompletion - previous.mileageAtCompletion;

      // Sanity checks: at least 14 days between and positive km
      if (daysBetween >= 14 && kmBetween > 0) {
        const rate = kmBetween / daysBetween;
        // Typical metro range: 50-500 km/day
        if (rate > 50 && rate < 500) {
          return {
            ...train,
            estimatedDailyKm: Math.round(rate),
            confidence: 'HISTORICAL' as const,
          };
        }
      }
    }

    // Fallback: lifetime average from commissioning
    const daysSinceCommission = Math.floor(
      (Date.now() - train.commissioningDate.getTime()) / (1000 * 60 * 60 * 24)
    );
    if (daysSinceCommission > 0 && train.currentMileageKm > 0) {
      const rate = train.currentMileageKm / daysSinceCommission;
      if (rate > 0 && rate < 1000) {
        return {
          ...train,
          estimatedDailyKm: Math.round(rate),
          confidence: 'HISTORICAL' as const,
        };
      }
    }

    // Last resort: keep default
    return train;
  });
}

