#!/usr/bin/env bun
/**
 * MMS Demo Data Generator CLI
 *
 * Usage:
 *   bun run src/demo/cli.ts [options]
 *
 * Options:
 *   --trains <number>     Number of trains to generate (default: 128)
 *   --history <years>     Years of historical data (default: 5)
 *   --bow-wave            Enable bow-wave scenario (Q2 2027 clustering)
 *   --seed <number>       Random seed for reproducible generation
 *   --output <file>       Output SQL file (default: stdout)
 *   --json                Output JSON instead of SQL
 *   --analyze             Analyze bow-wave scenario and output report
 *   --horizon <years>     Analysis horizon in years (default: 3)
 *
 * @example
 *   bun run src/demo/cli.ts --trains 128 --bow-wave --output drizzle/manual/seed_demo.sql
 *   bun run src/demo/cli.ts --trains 128 --bow-wave --analyze --json
 */

import { writeFileSync } from 'node:fs';
import { generateDemoData, generateSQL } from './generator';
import { analyzeBowWaveScenario, formatAnalysisReport } from './analyzer';

interface CliArgs {
  trains: number;
  history: number;
  bowWave: boolean;
  seed?: number;
  output?: string;
  json: boolean;
  analyze: boolean;
  horizon: number;
}

function parseArgs(): CliArgs {
  const args = process.argv.slice(2);
  const result: CliArgs = {
    trains: 128,
    history: 5,
    bowWave: false,
    json: false,
    analyze: false,
    horizon: 3,
  };

  for (let i = 0; i < args.length; i++) {
    const arg = args[i];

    switch (arg) {
      case '--trains':
        result.trains = parseInt(args[++i], 10);
        break;
      case '--history':
        result.history = parseInt(args[++i], 10);
        break;
      case '--bow-wave':
        result.bowWave = true;
        break;
      case '--seed':
        result.seed = parseInt(args[++i], 10);
        break;
      case '--output':
        result.output = args[++i];
        break;
      case '--json':
        result.json = true;
        break;
      case '--analyze':
        result.analyze = true;
        break;
      case '--horizon':
        result.horizon = parseInt(args[++i], 10);
        break;
      case '--help':
      case '-h':
        console.log(`
MMS Demo Data Generator

Usage:
  bun run src/demo/cli.ts [options]

Options:
  --trains <number>     Number of trains to generate (default: 128)
  --history <years>     Years of historical data (default: 5)
  --bow-wave            Enable bow-wave scenario (Q2 2027 clustering)
  --seed <number>       Random seed for reproducible generation
  --output <file>       Output SQL file (default: stdout)
  --json                Output JSON instead of SQL
  --analyze             Analyze bow-wave scenario and output report
  --horizon <years>     Analysis horizon in years (default: 3)
  --help, -h            Show this help message

Examples:
  # Generate 128-train demo data with bow-wave scenario
  bun run src/demo/cli.ts --trains 128 --bow-wave --output drizzle/manual/seed_demo.sql

  # Generate reproducible data with specific seed
  bun run src/demo/cli.ts --seed 12345 --output seed.sql

  # Generate JSON for API testing
  bun run src/demo/cli.ts --json > demo-data.json

  # Analyze bow-wave scenario (human-readable report)
  bun run src/demo/cli.ts --trains 128 --bow-wave --analyze

  # Analyze and output JSON for visualization
  bun run src/demo/cli.ts --trains 128 --bow-wave --analyze --json
`);
        process.exit(0);
    }
  }

  return result;
}

function main(): void {
  const args = parseArgs();

  console.error(`Generating demo data...`);
  console.error(`  Trains: ${args.trains}`);
  console.error(`  History: ${args.history} years`);
  console.error(`  Bow-wave: ${args.bowWave ? 'enabled' : 'disabled'}`);
  console.error(`  Analyze: ${args.analyze ? 'enabled' : 'disabled'}`);
  if (args.analyze) {
    console.error(`  Horizon: ${args.horizon} years`);
  }
  if (args.seed !== undefined) {
    console.error(`  Seed: ${args.seed}`);
  }

  const startTime = Date.now();

  const data = generateDemoData({
    trainCount: args.trains,
    historyYears: args.history,
    enableBowWave: args.bowWave,
    seed: args.seed,
  });

  const genTime = Date.now() - startTime;
  console.error(`\nGeneration complete in ${genTime}ms`);
  console.error(`  Depots: ${data.depots.length}`);
  console.error(`  Fleets: ${data.fleets.length}`);
  console.error(`  Trains: ${data.trains.length}`);
  console.error(`  PM Types: ${data.pmTypes.length}`);
  console.error(`  PM History: ${data.pmHistory.length}`);
  console.error(`  Mileage Readings: ${data.mileageReadings.length}`);
  console.error(`  Service Demand: ${data.serviceDemand.length}`);
  console.error(`  Tracks: ${data.tracks.length}`);

  let output: string;

  if (args.analyze) {
    // Run bow-wave analysis
    console.error(`\nAnalyzing bow-wave scenario...`);
    const analysisStartTime = Date.now();

    const analysisOutput = analyzeBowWaveScenario(data, { horizonYears: args.horizon });

    const analysisTime = Date.now() - analysisStartTime;
    console.error(`Analysis complete in ${analysisTime}ms`);
    console.error(`  Projected PMs: ${analysisOutput.projectedPMs.length}`);
    console.error(`  Critical Months: ${analysisOutput.monthlyDensity.filter((m) => m.isCritical).length}`);
    console.error(`  Risk Level: ${analysisOutput.analysis.riskLevel}`);

    if (args.json) {
      // Convert dates to ISO strings for JSON serialization
      const jsonOutput = {
        ...analysisOutput,
        projectedPMs: analysisOutput.projectedPMs.map((pm) => ({
          ...pm,
          projectedDate: pm.projectedDate.toISOString().split('T')[0],
        })),
      };
      output = JSON.stringify(jsonOutput, null, 2);
    } else {
      output = formatAnalysisReport(analysisOutput);
    }
  } else if (args.json) {
    // Convert dates to ISO strings for JSON serialization
    const jsonData = {
      ...data,
      trains: data.trains.map((t) => ({
        ...t,
        commissioningDate: t.commissioningDate.toISOString().split('T')[0],
      })),
      pmHistory: data.pmHistory.map((pm) => ({
        ...pm,
        completionDate: pm.completionDate.toISOString().split('T')[0],
      })),
      mileageReadings: data.mileageReadings.map((r) => ({
        ...r,
        readingDate: r.readingDate.toISOString().split('T')[0],
      })),
    };
    output = JSON.stringify(jsonData, null, 2);
  } else {
    output = generateSQL(data);
  }

  if (args.output) {
    writeFileSync(args.output, output);
    console.error(`\nOutput written to: ${args.output}`);
  } else {
    console.log(output);
  }
}

main();

