   294тЖТ      });
   295тЖТ
   296тЖТ      // Close modal after short delay
   297тЖТ      setTimeout(() => {
   298тЖТ        onClose();
   299тЖТ      }, 1500);
   300тЖТ    } catch (err) {
   301тЖТ      uiActions.updateModalData({
   302тЖТ        importStep: { step: 'error', progress: 0 },
   303тЖТ        error: err instanceof Error ? err.message : 'Failed to import data',
   304тЖТ      });
   305тЖТ    }
   306тЖТ  };
   307тЖТ
   308тЖТ  const handleCancel = () => {
   309тЖТ    if (importStep.step !== 'importing') {
   310тЖТ      uiActions.updateModalData({
   311тЖТ        fleetRosterFile: null,
   312тЖТ        pmHistoryFile: null,
   313тЖТ        pmRulesFile: null,
