   353тЖТ        validationResult: result,
   354тЖТ        error: result.success ? null : 'Sample data validation failed',
   355тЖТ      });
   356тЖТ    } catch (err) {
   357тЖТ      uiActions.updateModalData({
   358тЖТ        importStep: { step: 'error', progress: 0 },
   359тЖТ        error: err instanceof Error ? err.message : 'Failed to load sample data',
   360тЖТ      });
   361тЖТ    }
   362тЖТ  };
   363тЖТ
   364тЖТ  const isValidating = importStep.step === 'validating';
   365тЖТ  const isImporting = importStep.step === 'importing';
   366тЖТ  const isComplete = importStep.step === 'complete';
   367тЖТ  const canValidate = modalData.fleetRosterFile && modalData.pmHistoryFile && !isValidating;
   368тЖТ  const canImport = validationResult?.success && !isImporting && !isComplete;
   369тЖТ
   370тЖТ  return (
   371тЖТ    <Dialog
   372тЖТ      isOpen={isOpen}
   373тЖТ      onClose={handleCancel}
   374тЖТ      title="Import Fleet Data"
   375тЖТ      icon="import"
   376тЖТ      canEscapeKeyClose={!isImporting}
   377тЖТ      canOutsideClickClose={!isImporting}
   378тЖТ      data-testid="import-modal"
   379тЖТ      style={{ width: 560 }}
   380тЖТ    >
   381тЖТ      <DialogBody>
   382тЖТ        {/* Info Callout */}
   383тЖТ        <Callout intent={Intent.PRIMARY} icon="info-sign" style={{ marginBottom: 16 }}>
   384тЖТ          Import CSV files to load fleet roster and PM history data.
   385тЖТ          Download{' '}
   386тЖТ          <a href="/sample-data/fleet_roster_sample.csv" download>
   387тЖТ            sample files
   388тЖТ          </a>{' '}
   389тЖТ          for format reference.
   390тЖТ        </Callout>
   391тЖТ
   392тЖТ        {/* Error Display */}
   393тЖТ        {error && (
   394тЖТ          <Callout intent={Intent.DANGER} icon="error" style={{ marginBottom: 16 }}>
   395тЖТ            {error}
   396тЖТ          </Callout>
   397тЖТ        )}
   398тЖТ
   399тЖТ        {/* Success Display */}
   400тЖТ        {isComplete && (
   401тЖТ          <Callout intent={Intent.SUCCESS} icon="tick-circle" style={{ marginBottom: 16 }}>
   402тЖТ            Import completed successfully!
   403тЖТ          </Callout>
   404тЖТ        )}
   405тЖТ
   406тЖТ        {/* Progress Bar */}
   407тЖТ        {(isValidating || isImporting) && (
   408тЖТ          <div style={{ marginBottom: 16 }}>
   409тЖТ            <ProgressBar
   410тЖТ              intent={Intent.PRIMARY}
   411тЖТ              value={importStep.progress / 100}
   412тЖТ              animate={true}
   413тЖТ              stripes={true}
   414тЖТ            />
   415тЖТ            <div style={{ textAlign: 'center', marginTop: 8, fontSize: 12 }}>
   416тЖТ              {isValidating ? 'Validating files...' : 'Importing data...'}
   417тЖТ            </div>
   418тЖТ          </div>
   419тЖТ        )}
   420тЖТ
   421тЖТ        {/* File Inputs */}
   422тЖТ        <FormGroup
   423тЖТ          label="Fleet Roster CSV"
   424тЖТ          labelFor="fleet-roster"
   425тЖТ          labelInfo="(required)"
   426тЖТ          helperText="Columns: train_number, fleet_code, current_mileage_km, commissioning_date"
   427тЖТ        >
   428тЖТ          <FileInput
   429тЖТ            id="fleet-roster"
   430тЖТ            inputProps={{
   431тЖТ              ref: fleetRosterRef,
   432тЖТ              accept: '.csv',
   433тЖТ              onChange: handleFleetRosterChange,
   434тЖТ            }}
   435тЖТ            text={modalData.fleetRosterFile?.name ?? 'Choose file...'}
   436тЖТ            disabled={isValidating || isImporting}
   437тЖТ            fill
   438тЖТ            data-testid="fleet-roster-input"
   439тЖТ          />
