   467тЖТ        >
   468тЖТ          <FileInput
   469тЖТ            id="pm-rules"
   470тЖТ            inputProps={{
   471тЖТ              ref: pmRulesRef,
   472тЖТ              accept: '.csv',
   473тЖТ              onChange: handlePmRulesChange,
   474тЖТ            }}
   475тЖТ            text={modalData.pmRulesFile?.name ?? 'Choose file... (optional)'}
   476тЖТ            disabled={isValidating || isImporting}
   477тЖТ            fill
