   492тЖТ          </Button>
   493тЖТ        </div>
   494тЖТ
   495тЖТ        {/* Validation Results */}
   496тЖТ        {validationResult && (
   497тЖТ          <div style={{ marginTop: 16 }}>
   498тЖТ            <h5 style={{ marginBottom: 8 }}>Validation Results</h5>
   499тЖТ            <div style={{ display: 'flex', gap: 16, marginBottom: 8 }}>
   500тЖТ              <div>
   501тЖТ                <Tag intent={validationResult.stats.trains.valid > 0 ? Intent.SUCCESS : Intent.DANGER}>
   502тЖТ                  Trains: {validationResult.stats.trains.valid} valid
   503тЖТ                </Tag>
   504тЖТ                {validationResult.stats.trains.invalid > 0 && (
   505тЖТ                  <Tag intent={Intent.WARNING} style={{ marginLeft: 4 }}>
   506тЖТ                    {validationResult.stats.trains.invalid} invalid
   507тЖТ                  </Tag>
   508тЖТ                )}
   509тЖТ              </div>
   510тЖТ              <div>
   511тЖТ                <Tag intent={validationResult.stats.pmHistory.valid > 0 ? Intent.SUCCESS : Intent.WARNING}>
   512тЖТ                  PM Records: {validationResult.stats.pmHistory.valid} valid
   513тЖТ                </Tag>
   514тЖТ                {validationResult.stats.pmHistory.invalid > 0 && (
   515тЖТ                  <Tag intent={Intent.WARNING} style={{ marginLeft: 4 }}>
   516тЖТ                    {validationResult.stats.pmHistory.invalid} invalid
   517тЖТ                  </Tag>
   518тЖТ                )}
   519тЖТ              </div>
   520тЖТ            </div>
   521тЖТ
   522тЖТ            {/* Validation Errors */}
   523тЖТ            {validationResult.errors.length > 0 && (
   524тЖТ              <Callout
   525тЖТ                intent={Intent.WARNING}
