   530тЖТ                <ul style={{ margin: '8px 0 0 0', paddingLeft: 20 }}>
   531тЖТ                  {validationResult.errors.slice(0, 10).map((err, i) => (
   532тЖТ                    <li key={i} style={{ fontSize: 12 }}>
   533тЖТ                      Row {err.row}: {err.field} - {err.message}
   534тЖТ                    </li>
   535тЖТ                  ))}
   536тЖТ                  {validationResult.errors.length > 10 && (
   537тЖТ                    <li style={{ fontSize: 12 }}>
   538тЖТ                      ...and {validationResult.errors.length - 10} more
   539тЖТ                    </li>
   540тЖТ                  )}
   541тЖТ                </ul>
   542тЖТ              </Callout>
   543тЖТ            )}
   544тЖТ
   545тЖТ            {/* Warnings */}
   546тЖТ            {validationResult.warnings.length > 0 && (
   547тЖТ              <Callout
   548тЖТ                intent={Intent.PRIMARY}
   549тЖТ                icon="info-sign"
   550тЖТ                style={{ marginTop: 8, maxHeight: 100, overflow: 'auto' }}
   551тЖТ              >
   552тЖТ                <strong>Warnings ({validationResult.warnings.length}):</strong>
   553тЖТ                <ul style={{ margin: '8px 0 0 0', paddingLeft: 20 }}>
   554тЖТ                  {validationResult.warnings.slice(0, 5).map((warn, i) => (
   555тЖТ                    <li key={i} style={{ fontSize: 12 }}>
   556тЖТ                      {warn}
   557тЖТ                    </li>
   558тЖТ                  ))}
   559тЖТ                  {validationResult.warnings.length > 5 && (
   560тЖТ                    <li style={{ fontSize: 12 }}>
   561тЖТ                      ...and {validationResult.warnings.length - 5} more
   562тЖТ                    </li>
   563тЖТ                  )}
   564тЖТ                </ul>
   565тЖТ              </Callout>
   566тЖТ            )}
   567тЖТ          </div>
   568тЖТ        )}
   569тЖТ      </DialogBody>
   570тЖТ
   571тЖТ      <DialogFooter
   572тЖТ        actions={
   573тЖТ          <>
   574тЖТ            <Button onClick={handleCancel} disabled={isImporting}>
   575тЖТ              Cancel
   576тЖТ            </Button>
   577тЖТ            {!validationResult && (
   578тЖТ              <Button
   579тЖТ                intent={Intent.PRIMARY}
   580тЖТ                onClick={handleValidate}
   581тЖТ                disabled={!canValidate}
   582тЖТ                icon={isValidating ? undefined : 'endorsed'}
   583тЖТ              >
   584тЖТ                {isValidating ? (
   585тЖТ                  <>
   586тЖТ                    <Spinner size={16} /> Validating...
   587тЖТ                  </>
   588тЖТ                ) : (
   589тЖТ                  'Validate'
   590тЖТ                )}
