/**
 * Import Modal
 *
 * Modal dialog for importing CSV data (fleet roster, PM history).
 * Uses PapaParse for CSV parsing with validation feedback.
 *
 * @see specs/009-demo-application.md Section 9.2.1
 */

import { useRef } from 'react';
import {
  Dialog,
  DialogBody,
  DialogFooter,
  Button,
  Intent,
  FormGroup,
  FileInput,
  Callout,
  Spinner,
  Tag,
  ProgressBar,
} from '@blueprintjs/core';
import { v4 as uuidv4 } from 'uuid';

import { useUi, useFleet, usePm } from '../../store';
import type { UiSliceState } from '../../store/slices/ui';
import type { Train, Fleet, PmScheduleEntry } from '../../store/types';
import {
  importDemoData,
  type DemoImportResult,
  type ImportedTrain,
  type ImportedPMHistory,
} from '../../demo/csv-import';
import { DEMO_FLEETS } from '../../demo/data';

// =============================================================================
// Modal Data Interface
// =============================================================================

interface ImportStep {
  step: 'select' | 'validating' | 'importing' | 'complete' | 'error';
  progress: number;
}

interface ImportModalData {
  fleetRosterFile?: File | null;
  pmHistoryFile?: File | null;
  pmRulesFile?: File | null;
  importStep?: ImportStep;
  validationResult?: DemoImportResult | null;
  error?: string | null;
}

// =============================================================================
// Fleet Color Mapping
// =============================================================================

const FLEET_COLORS: Record<string, string> = {
  ML: '#1E88E5',
  AEL: '#43A047',
  TCL: '#FB8C00',
};

// =============================================================================
// Component
// =============================================================================

export interface ImportModalProps {
  isOpen: boolean;
  onClose: () => void;
}

export function ImportModal({ isOpen, onClose }: ImportModalProps) {
  const { state: uiStateRaw, actions: uiActions } = useUi();
  const { actions: fleetActions } = useFleet();
  const { actions: pmActions } = usePm();

  const uiState = uiStateRaw as unknown as UiSliceState;

  // File input refs
  const fleetRosterRef = useRef<HTMLInputElement>(null);
  const pmHistoryRef = useRef<HTMLInputElement>(null);
  const pmRulesRef = useRef<HTMLInputElement>(null);

  // Modal state
  const modalData = (uiState.modal.data || {}) as ImportModalData;
  const importStep = modalData.importStep ?? { step: 'select', progress: 0 };
  const validationResult = modalData.validationResult ?? null;
  const error = modalData.error ?? null;

  const handleFleetRosterChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0] ?? null;
    uiActions.updateModalData({
      fleetRosterFile: file,
      validationResult: null,
      error: null,
    });
  };

  const handlePmHistoryChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0] ?? null;
    uiActions.updateModalData({
      pmHistoryFile: file,
      validationResult: null,
      error: null,
    });
  };

  const handlePmRulesChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0] ?? null;
    uiActions.updateModalData({ pmRulesFile: file });
  };

  const readFileAsText = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = () => reject(new Error(`Failed to read file: ${file.name}`));
      reader.readAsText(file);
    });
  };

  const handleValidate = async () => {
    const fleetRosterFile = modalData.fleetRosterFile;
    const pmHistoryFile = modalData.pmHistoryFile;
    const pmRulesFile = modalData.pmRulesFile;

    if (!fleetRosterFile || !pmHistoryFile) {
      uiActions.updateModalData({
        error: 'Fleet roster and PM history files are required',
      });
      return;
    }

    try {
      uiActions.updateModalData({
        importStep: { step: 'validating', progress: 0 },
        error: null,
      });

      // Read files
      const fleetRosterCsv = await readFileAsText(fleetRosterFile);
      uiActions.updateModalData({
        importStep: { step: 'validating', progress: 33 },
      });

      const pmHistoryCsv = await readFileAsText(pmHistoryFile);
      uiActions.updateModalData({
        importStep: { step: 'validating', progress: 66 },
      });

      let pmRulesCsv: string | undefined;
      if (pmRulesFile) {
        pmRulesCsv = await readFileAsText(pmRulesFile);
      }

      // Parse and validate
      const result = importDemoData({
        fleetRoster: fleetRosterCsv,
        pmHistory: pmHistoryCsv,
        pmRules: pmRulesCsv,
      });

      uiActions.updateModalData({
        importStep: { step: 'select', progress: 100 },
        validationResult: result,
        error: result.success ? null : 'Validation failed - check errors below',
      });
    } catch (err) {
      uiActions.updateModalData({
        importStep: { step: 'error', progress: 0 },
        error: err instanceof Error ? err.message : 'Failed to validate files',
      });
    }
  };

  const convertToStoreFormat = (
    importedTrains: ImportedTrain[],
    pmHistory: ImportedPMHistory[]
  ): { trains: Train[]; fleets: Fleet[]; pmSchedule: PmScheduleEntry[] } => {
    // Group trains by fleet to create Fleet entities
    const fleetMap = new Map<string, Fleet>();
    const trains: Train[] = [];

    for (const imported of importedTrains) {
      // Get or create fleet
      let fleet = fleetMap.get(imported.fleetCode);
      if (!fleet) {
        const demoFleet = DEMO_FLEETS.find((f) => f.code === imported.fleetCode);
        fleet = {
          id: uuidv4(),
          code: imported.fleetCode,
          name: demoFleet?.name ?? `${imported.fleetCode} Fleet`,
          manufacturer: demoFleet?.manufacturer ?? null,
          carsPerTrain: demoFleet?.carsPerTrain ?? 8,
          baseDepotId: null,
          displayColor: FLEET_COLORS[imported.fleetCode] ?? '#6B7280',
        };
        fleetMap.set(imported.fleetCode, fleet);
      }

      // Create train
      const train: Train = {
        id: uuidv4(),
        trainNumber: imported.trainNumber,
        fleetId: fleet.id,
        fleetCode: imported.fleetCode,
        currentMileageKm: imported.currentMileageKm,
        targetMileageKm: null,
        fitnessStatus: 'FIT',
        fitnessNotes: null,
        currentDepotId: null,
        homeDepotId: null,
        displayColor: fleet.displayColor,
        commissioningDate: imported.commissioningDate.toISOString().split('T')[0],
        updatedAt: new Date().toISOString(),
      };
      trains.push(train);
    }

    // Convert PM history to schedule entries
    const pmSchedule: PmScheduleEntry[] = [];
    const trainIdByNumber = new Map(trains.map((t) => [t.trainNumber, t.id]));

    for (const pm of pmHistory) {
      const trainId = trainIdByNumber.get(pm.trainNumber);
      if (!trainId) continue;

      const entry: PmScheduleEntry = {
        id: uuidv4(),
        trainId,
        trainNumber: pm.trainNumber,
        pmTypeId: uuidv4(),
        pmCode: pm.pmCode,
        targetDate: pm.completionDate.toISOString().split('T')[0],
        status: 'COMPLETED',
        constraintStart: null,
        constraintEnd: null,
        assignedTrackId: null,
        isLocked: false,
        lockedBy: null,
        lockedAt: null,
        scenarioId: null,
        estimatedHours: 8,
        displayColor: '#1E88E5',
      };
      pmSchedule.push(entry);
    }

    return {
      trains,
      fleets: Array.from(fleetMap.values()),
      pmSchedule,
    };
  };

  const handleImport = async () => {
    if (!validationResult?.fleetState) {
      uiActions.updateModalData({
        error: 'No valid data to import. Please validate files first.',
      });
      return;
    }

    try {
      uiActions.updateModalData({
        importStep: { step: 'importing', progress: 0 },
        error: null,
      });

      const { trains: importedTrains, pmHistory } = validationResult.fleetState;

      // Convert to store format
      const { trains, fleets, pmSchedule } = convertToStoreFormat(importedTrains, pmHistory);

      uiActions.updateModalData({
        importStep: { step: 'importing', progress: 50 },
      });

      // Update stores
      fleetActions.setFleets(fleets);
      fleetActions.setTrains(trains);
      pmActions.setPmSchedule(pmSchedule);

      uiActions.updateModalData({
        importStep: { step: 'complete', progress: 100 },
      });

      // Show success
      uiActions.showSuccess({
        title: 'Import Complete',
        message: `Imported ${trains.length} trains with ${pmSchedule.length} PM records.`,
      });

      // Close modal after short delay
      setTimeout(() => {
        onClose();
      }, 1500);
    } catch (err) {
      uiActions.updateModalData({
        importStep: { step: 'error', progress: 0 },
        error: err instanceof Error ? err.message : 'Failed to import data',
      });
    }
  };

  const handleCancel = () => {
    if (importStep.step !== 'importing') {
      uiActions.updateModalData({
        fleetRosterFile: null,
        pmHistoryFile: null,
        pmRulesFile: null,
        importStep: { step: 'select', progress: 0 },
        validationResult: null,
        error: null,
      });
      onClose();
    }
  };

  const handleLoadSample = async () => {
    try {
      uiActions.updateModalData({
        importStep: { step: 'validating', progress: 0 },
        error: null,
      });

      // Fetch sample files from public directory
      const [rosterRes, historyRes, rulesRes] = await Promise.all([
        fetch('/sample-data/fleet_roster_sample.csv'),
        fetch('/sample-data/pm_history_sample.csv'),
        fetch('/sample-data/pm_rules_default.csv'),
      ]);

      if (!rosterRes.ok || !historyRes.ok) {
        throw new Error('Failed to load sample files');
      }

      const fleetRosterCsv = await rosterRes.text();
      const pmHistoryCsv = await historyRes.text();
      const pmRulesCsv = rulesRes.ok ? await rulesRes.text() : undefined;

      // Parse and validate
      const result = importDemoData({
        fleetRoster: fleetRosterCsv,
        pmHistory: pmHistoryCsv,
        pmRules: pmRulesCsv,
      });

      uiActions.updateModalData({
        importStep: { step: 'select', progress: 100 },
        validationResult: result,
        error: result.success ? null : 'Sample data validation failed',
      });
    } catch (err) {
      uiActions.updateModalData({
        importStep: { step: 'error', progress: 0 },
        error: err instanceof Error ? err.message : 'Failed to load sample data',
      });
    }
  };

  const isValidating = importStep.step === 'validating';
  const isImporting = importStep.step === 'importing';
  const isComplete = importStep.step === 'complete';
  const canValidate = modalData.fleetRosterFile && modalData.pmHistoryFile && !isValidating;
  const canImport = validationResult?.success && !isImporting && !isComplete;

  return (
    <Dialog
      isOpen={isOpen}
      onClose={handleCancel}
      title="Import Fleet Data"
      icon="import"
      canEscapeKeyClose={!isImporting}
      canOutsideClickClose={!isImporting}
      data-testid="import-modal"
      style={{ width: 560 }}
    >
      <DialogBody>
        {/* Info Callout */}
        <Callout intent={Intent.PRIMARY} icon="info-sign" style={{ marginBottom: 16 }}>
          Import CSV files to load fleet roster and PM history data.
          Download{' '}
          <a href="/sample-data/fleet_roster_sample.csv" download>
            sample files
          </a>{' '}
          for format reference.
        </Callout>

        {/* Error Display */}
        {error && (
          <Callout intent={Intent.DANGER} icon="error" style={{ marginBottom: 16 }}>
            {error}
          </Callout>
        )}

        {/* Success Display */}
        {isComplete && (
          <Callout intent={Intent.SUCCESS} icon="tick-circle" style={{ marginBottom: 16 }}>
            Import completed successfully!
          </Callout>
        )}

        {/* Progress Bar */}
        {(isValidating || isImporting) && (
          <div style={{ marginBottom: 16 }}>
            <ProgressBar
              intent={Intent.PRIMARY}
              value={importStep.progress / 100}
              animate={true}
              stripes={true}
            />
            <div style={{ textAlign: 'center', marginTop: 8, fontSize: 12 }}>
              {isValidating ? 'Validating files...' : 'Importing data...'}
            </div>
          </div>
        )}

        {/* File Inputs */}
        <FormGroup
          label="Fleet Roster CSV"
          labelFor="fleet-roster"
          labelInfo="(required)"
          helperText="Columns: train_number, fleet_code, current_mileage_km, commissioning_date"
        >
          <FileInput
            id="fleet-roster"
            inputProps={{
              ref: fleetRosterRef,
              accept: '.csv',
              onChange: handleFleetRosterChange,
            }}
            text={modalData.fleetRosterFile?.name ?? 'Choose file...'}
            disabled={isValidating || isImporting}
            fill
            data-testid="fleet-roster-input"
          />
        </FormGroup>

        <FormGroup
          label="PM History CSV"
          labelFor="pm-history"
          labelInfo="(required)"
          helperText="Columns: train_number, pm_code, completion_date, mileage_at_completion"
        >
          <FileInput
            id="pm-history"
            inputProps={{
              ref: pmHistoryRef,
              accept: '.csv',
              onChange: handlePmHistoryChange,
            }}
            text={modalData.pmHistoryFile?.name ?? 'Choose file...'}
            disabled={isValidating || isImporting}
            fill
            data-testid="pm-history-input"
          />
        </FormGroup>

        <FormGroup
          label="PM Rules CSV"
          labelFor="pm-rules"
          labelInfo="(optional)"
          helperText="Custom PM intervals. Uses defaults if not provided."
        >
          <FileInput
            id="pm-rules"
            inputProps={{
              ref: pmRulesRef,
              accept: '.csv',
              onChange: handlePmRulesChange,
            }}
            text={modalData.pmRulesFile?.name ?? 'Choose file... (optional)'}
            disabled={isValidating || isImporting}
            fill
            data-testid="pm-rules-input"
          />
        </FormGroup>

        {/* Sample Data Button */}
        <div style={{ textAlign: 'center', marginTop: 16, marginBottom: 16 }}>
          <Button
            minimal
            intent={Intent.PRIMARY}
            icon="download"
            onClick={handleLoadSample}
            disabled={isValidating || isImporting}
          >
            Load Sample Data
          </Button>
        </div>

        {/* Validation Results */}
        {validationResult && (
          <div style={{ marginTop: 16 }}>
            <h5 style={{ marginBottom: 8 }}>Validation Results</h5>
            <div style={{ display: 'flex', gap: 16, marginBottom: 8 }}>
              <div>
                <Tag intent={validationResult.stats.trains.valid > 0 ? Intent.SUCCESS : Intent.DANGER}>
                  Trains: {validationResult.stats.trains.valid} valid
                </Tag>
                {validationResult.stats.trains.invalid > 0 && (
                  <Tag intent={Intent.WARNING} style={{ marginLeft: 4 }}>
                    {validationResult.stats.trains.invalid} invalid
                  </Tag>
                )}
              </div>
              <div>
                <Tag intent={validationResult.stats.pmHistory.valid > 0 ? Intent.SUCCESS : Intent.WARNING}>
                  PM Records: {validationResult.stats.pmHistory.valid} valid
                </Tag>
                {validationResult.stats.pmHistory.invalid > 0 && (
                  <Tag intent={Intent.WARNING} style={{ marginLeft: 4 }}>
                    {validationResult.stats.pmHistory.invalid} invalid
                  </Tag>
                )}
              </div>
            </div>

            {/* Validation Errors */}
            {validationResult.errors.length > 0 && (
              <Callout
                intent={Intent.WARNING}
                icon="warning-sign"
                style={{ maxHeight: 150, overflow: 'auto' }}
              >
                <strong>Errors ({validationResult.errors.length}):</strong>
                <ul style={{ margin: '8px 0 0 0', paddingLeft: 20 }}>
                  {validationResult.errors.slice(0, 10).map((err, i) => (
                    <li key={i} style={{ fontSize: 12 }}>
                      Row {err.row}: {err.field} - {err.message}
                    </li>
                  ))}
                  {validationResult.errors.length > 10 && (
                    <li style={{ fontSize: 12 }}>
                      ...and {validationResult.errors.length - 10} more
                    </li>
                  )}
                </ul>
              </Callout>
            )}

            {/* Warnings */}
            {validationResult.warnings.length > 0 && (
              <Callout
                intent={Intent.PRIMARY}
                icon="info-sign"
                style={{ marginTop: 8, maxHeight: 100, overflow: 'auto' }}
              >
                <strong>Warnings ({validationResult.warnings.length}):</strong>
                <ul style={{ margin: '8px 0 0 0', paddingLeft: 20 }}>
                  {validationResult.warnings.slice(0, 5).map((warn, i) => (
                    <li key={i} style={{ fontSize: 12 }}>
                      {warn}
                    </li>
                  ))}
                  {validationResult.warnings.length > 5 && (
                    <li style={{ fontSize: 12 }}>
                      ...and {validationResult.warnings.length - 5} more
                    </li>
                  )}
                </ul>
              </Callout>
            )}
          </div>
        )}
      </DialogBody>

      <DialogFooter
        actions={
          <>
            <Button onClick={handleCancel} disabled={isImporting}>
              Cancel
            </Button>
            {!validationResult && (
              <Button
                intent={Intent.PRIMARY}
                onClick={handleValidate}
                disabled={!canValidate}
                icon={isValidating ? undefined : 'endorsed'}
              >
                {isValidating ? (
                  <>
                    <Spinner size={16} /> Validating...
                  </>
                ) : (
                  'Validate'
                )}
              </Button>
            )}
            {validationResult && (
              <Button
                intent={Intent.SUCCESS}
                onClick={handleImport}
                disabled={!canImport}
                icon={isImporting ? undefined : 'import'}
              >
                {isImporting ? (
                  <>
                    <Spinner size={16} /> Importing...
                  </>
                ) : isComplete ? (
                  'Done'
                ) : (
                  'Import Data'
                )}
              </Button>
            )}
          </>
        }
      />
    </Dialog>
  );
}

export default ImportModal;

