     1тЖТ/**
     2тЖТ * BowWaveIndicator Component
     3тЖТ *
     4тЖТ * Displays bow-wave risk status for maintenance clustering visualization.
     5тЖТ * Bow-wave occurs when PM work accumulates in later periods, causing
     6тЖТ * operational overload and potential service disruptions.
     7тЖТ *
     8тЖТ * This component shows:
     9тЖТ * - Current risk level (LOW/MEDIUM/HIGH/CRITICAL)
    10тЖТ * - Risk score (0-100%)
    11тЖТ * - Peak periods requiring attention
    12тЖТ * - Actionable recommendations
    13тЖТ *
    14тЖТ * @see specs/006-user-interface.md Section 6.5 - Overlay Panels
    15тЖТ * @see specs/004-domain-services.md Section 4.6 - Strategic Planner (bow-wave detection)
    16тЖТ */
    17тЖТ
    18тЖТimport {
    19тЖТ  Tag,
    20тЖТ  Intent,
    21тЖТ  Popover,
    22тЖТ  Menu,
    23тЖТ  MenuItem,
    24тЖТ  MenuDivider,
    25тЖТ  ProgressBar,
    26тЖТ  Tooltip,
    27тЖТ  Spinner,
    28тЖТ  Classes,
    29тЖТ} from '@blueprintjs/core';
    30тЖТ
    31тЖТimport { useOverlay } from '../store';
    32тЖТimport type { OverlaySliceState } from '../store/slices/overlay';
    33тЖТimport {
    34тЖТ  selectBowWaveRiskDisplay,
    35тЖТ  selectBowWavePeakPeriods,
    36тЖТ  selectBowWaveHighPriorityRecommendations,
    37тЖТ  selectBowWaveSummary,
    38тЖТ  loadBowWaveOverlayData,
    39тЖТ  type BowWaveRiskLevel,
    40тЖТ  type BowWavePeakPeriod,
    41тЖТ  type BowWaveRecommendation,
    42тЖТ} from '../store/slices/overlay';
    43тЖТimport { isChaosMonkeyEnabled, toggleChaosMonkeyUrl } from '../demo/chaosMonkey';
    44тЖТ
    45тЖТ// =============================================================================
    46тЖТ// Types
    47тЖТ// =============================================================================
    48тЖТ
    49тЖТinterface BowWaveIndicatorProps {
    50тЖТ  /** Show compact version for toolbar */
    51тЖТ  compact?: boolean;
    52тЖТ  /** Fleet ID to filter by */
    53тЖТ  fleetId?: string;
    54тЖТ  /** Plan ID to show specific plan's bow-wave analysis */
    55тЖТ  planId?: string;
    56тЖТ  /** Custom class name */
    57тЖТ  className?: string;
    58тЖТ}
    59тЖТ
    60тЖТ// =============================================================================
    61тЖТ// Color Mapping
    62тЖТ// =============================================================================
    63тЖТ
    64тЖТconst RISK_INTENT_MAP: Record<BowWaveRiskLevel, Intent> = {
    65тЖТ  LOW: 'success',
    66тЖТ  MEDIUM: 'warning',
    67тЖТ  HIGH: 'warning',
    68тЖТ  CRITICAL: 'danger',
    69тЖТ};
    70тЖТ
    71тЖТconst RISK_ICON_MAP: Record<BowWaveRiskLevel, 'tick-circle' | 'warning-sign' | 'error'> = {
    72тЖТ  LOW: 'tick-circle',
    73тЖТ  MEDIUM: 'warning-sign',
    74тЖТ  HIGH: 'warning-sign',
    75тЖТ  CRITICAL: 'error',
    76тЖТ};
    77тЖТ
    78тЖТconst RECOMMENDATION_ICON_MAP: Record<BowWaveRecommendation['type'], 'arrow-left' | 'arrow-right' | 'people' | 'horizontal-distribution'> = {
    79тЖТ  ADVANCE_PM: 'arrow-left',
    80тЖТ  DEFER_PM: 'arrow-right',
    81тЖТ  ADD_CAPACITY: 'people',
    82тЖТ  SPREAD_WORKLOAD: 'horizontal-distribution',
    83тЖТ};
    84тЖТ
    85тЖТ// =============================================================================
    86тЖТ// Helper Components
    87тЖТ// =============================================================================
    88тЖТ
    89тЖТfunction RiskProgressBar({
    90тЖТ  riskScore,
    91тЖТ  riskLevel,
    92тЖТ}: {
    93тЖТ  riskScore: number;
    94тЖТ  riskLevel: BowWaveRiskLevel;
    95тЖТ}) {
    96тЖТ  const intent = RISK_INTENT_MAP[riskLevel];
    97тЖТ
    98тЖТ  return (
    99тЖТ    <div style={{ marginTop: 8 }}>
   100тЖТ      <div
   101тЖТ        style={{
   102тЖТ          display: 'flex',
   103тЖТ          justifyContent: 'space-between',
   104тЖТ          marginBottom: 4,
   105тЖТ          fontSize: 11,
   106тЖТ        }}
   107тЖТ      >
   108тЖТ        <span className={Classes.TEXT_MUTED}>Risk Score</span>
   109тЖТ        <span style={{ fontWeight: 500 }}>{Math.round(riskScore * 100)}%</span>
   110тЖТ      </div>
   111тЖТ      <ProgressBar
   112тЖТ        value={riskScore}
   113тЖТ        intent={intent}
   114тЖТ        stripes={riskLevel === 'CRITICAL'}
   115тЖТ        animate={riskLevel === 'CRITICAL'}
   116тЖТ      />
   117тЖТ    </div>
   118тЖТ  );
   119тЖТ}
   120тЖТ
   121тЖТfunction PeakPeriodItem({ period }: { period: BowWavePeakPeriod }) {
   122тЖТ  const intent = RISK_INTENT_MAP[period.riskLevel];
   123тЖТ
   124тЖТ  return (
   125тЖТ    <MenuItem
   126тЖТ      icon="calendar"
   127тЖТ      text={`${period.startQuarter} - ${period.endQuarter}`}
   128тЖТ      labelElement={
   129тЖТ        <Tag minimal intent={intent}>
   130тЖТ          {period.peakLoad} PMs/mo
   131тЖТ        </Tag>
   132тЖТ      }
   133тЖТ    />
   134тЖТ  );
   135тЖТ}
   136тЖТ
   137тЖТfunction RecommendationItem({ rec }: { rec: BowWaveRecommendation }) {
   138тЖТ  const priorityIntent: Intent =
   139тЖТ    rec.priority === 'HIGH' ? 'danger' : rec.priority === 'MEDIUM' ? 'warning' : 'none';
   140тЖТ
   141тЖТ  return (
   142тЖТ    <MenuItem
   143тЖТ      icon={RECOMMENDATION_ICON_MAP[rec.type]}
   144тЖТ      text={rec.description}
   145тЖТ      labelElement={
   146тЖТ        <Tag minimal intent={priorityIntent}>
   147тЖТ          {rec.priority}
   148тЖТ        </Tag>
   149тЖТ      }
   150тЖТ    />
   151тЖТ  );
   152тЖТ}
   153тЖТ
   154тЖТ// =============================================================================
   155тЖТ// Popover Content
   156тЖТ// =============================================================================
   157тЖТ
   158тЖТfunction BowWavePopoverContent({
   159тЖТ  state,
   160тЖТ  onRefresh,
   161тЖТ}: {
   162тЖТ  state: OverlaySliceState;
   163тЖТ  onRefresh: () => void;
   164тЖТ}) {
   165тЖТ  const riskDisplay = selectBowWaveRiskDisplay(state);
   166тЖТ  const peakPeriods = selectBowWavePeakPeriods(state);
   167тЖТ  const recommendations = selectBowWaveHighPriorityRecommendations(state);
   168тЖТ  const summary = selectBowWaveSummary(state);
   169тЖТ
   170тЖТ  if (state.bowWaveLoading) {
   171тЖТ    return (
   172тЖТ      <Menu>
   173тЖТ        <MenuItem
   174тЖТ          disabled
   175тЖТ          icon={<Spinner size={16} />}
   176тЖТ          text="Loading bow-wave analysis..."
   177тЖТ        />
   178тЖТ      </Menu>
   179тЖТ    );
   180тЖТ  }
   181тЖТ
   182тЖТ  if (state.bowWaveError) {
   183тЖТ    return (
   184тЖТ      <Menu>
   185тЖТ        <MenuItem
   186тЖТ          disabled
   187тЖТ          icon="error"
   188тЖТ          intent="danger"
   189тЖТ          text={`Error: ${state.bowWaveError}`}
   190тЖТ        />
   191тЖТ        <MenuDivider />
   192тЖТ        <MenuItem icon="refresh" text="Retry" onClick={onRefresh} />
   193тЖТ      </Menu>
   194тЖТ    );
   195тЖТ  }
   196тЖТ
   197тЖТ  if (!state.bowWaveData) {
   198тЖТ    return (
   199тЖТ      <Menu>
   200тЖТ        <MenuItem
   201тЖТ          disabled
   202тЖТ          icon="info-sign"
   203тЖТ          text="No bow-wave data available"
   204тЖТ        />
   205тЖТ        <MenuDivider />
   206тЖТ        <MenuItem icon="refresh" text="Load Analysis" onClick={onRefresh} />
   207тЖТ      </Menu>
   208тЖТ    );
   209тЖТ  }
   210тЖТ
   211тЖТ  const { bowWaveData } = state;
   212тЖТ
   213тЖТ  return (
   214тЖТ    <Menu style={{ maxWidth: 400 }}>
   215тЖТ      {/* Header with Risk Level */}
   216тЖТ      <div style={{ padding: '8px 12px' }}>
   217тЖТ        <div
   218тЖТ          style={{
   219тЖТ            display: 'flex',
   220тЖТ            alignItems: 'center',
   221тЖТ            justifyContent: 'space-between',
   222тЖТ            marginBottom: 8,
   223тЖТ          }}
   224тЖТ        >
   225тЖТ          <span style={{ fontWeight: 600, fontSize: 14 }}>{riskDisplay.label}</span>
   226тЖТ          <Tag
   227тЖТ            large
   228тЖТ            intent={RISK_INTENT_MAP[riskDisplay.level]}
   229тЖТ            icon={RISK_ICON_MAP[riskDisplay.level]}
   230тЖТ          >
   231тЖТ            {riskDisplay.level}
   232тЖТ          </Tag>
   233тЖТ        </div>
   234тЖТ
   235тЖТ        <RiskProgressBar
   236тЖТ          riskScore={bowWaveData.riskScore}
   237тЖТ          riskLevel={riskDisplay.level}
   238тЖТ        />
   239тЖТ      </div>
   240тЖТ
   241тЖТ      <MenuDivider />
   242тЖТ
   243тЖТ      {/* Summary Stats */}
   244тЖТ      {summary && (
   245тЖТ        <>
   246тЖТ          <div style={{ padding: '8px 12px' }}>
   247тЖТ            <div className={Classes.TEXT_MUTED} style={{ fontSize: 11, marginBottom: 6 }}>
   248тЖТ              Load Distribution
   249тЖТ            </div>
   250тЖТ            <div
   251тЖТ              style={{
   252тЖТ                display: 'grid',
   253тЖТ                gridTemplateColumns: '1fr 1fr',
   254тЖТ                gap: 8,
   255тЖТ                fontSize: 12,
   256тЖТ              }}
   257тЖТ            >
   258тЖТ              <div>
   259тЖТ                <span className={Classes.TEXT_MUTED}>First Half: </span>
   260тЖТ                <span style={{ fontWeight: 500 }}>{summary.firstHalfLoad} PMs</span>
   261тЖТ              </div>
   262тЖТ              <div>
   263тЖТ                <span className={Classes.TEXT_MUTED}>Second Half: </span>
   264тЖТ                <span style={{ fontWeight: 500 }}>{summary.secondHalfLoad} PMs</span>
   265тЖТ              </div>
   266тЖТ              <div>
   267тЖТ                <span className={Classes.TEXT_MUTED}>Imbalance: </span>
   268тЖТ                <span
   269тЖТ                  style={{
   270тЖТ                    fontWeight: 500,
   271тЖТ                    color:
   272тЖТ                      summary.loadImbalanceRatio > 1.5
   273тЖТ                        ? '#DC2626'
   274тЖТ                        : summary.loadImbalanceRatio > 1.2
   275тЖТ                          ? '#F59E0B'
   276тЖТ                          : '#10B981',
   277тЖТ                  }}
   278тЖТ                >
   279тЖТ                  {summary.loadImbalanceRatio.toFixed(2)}x
   280тЖТ                </span>
   281тЖТ              </div>
   282тЖТ              <div>
   283тЖТ                <span className={Classes.TEXT_MUTED}>Total: </span>
   284тЖТ                <span style={{ fontWeight: 500 }}>{summary.totalPms} PMs</span>
   285тЖТ              </div>
   286тЖТ            </div>
   287тЖТ          </div>
   288тЖТ          <MenuDivider />
   289тЖТ        </>
   290тЖТ      )}
   291тЖТ
   292тЖТ      {/* Peak Periods */}
   293тЖТ      {peakPeriods.length > 0 && (
   294тЖТ        <>
   295тЖТ          <MenuItem disabled text="Peak Periods" icon="timeline-events" />
   296тЖТ          {peakPeriods.slice(0, 3).map((period, idx) => (
   297тЖТ            <PeakPeriodItem key={idx} period={period} />
   298тЖТ          ))}
   299тЖТ          {peakPeriods.length > 3 && (
   300тЖТ            <MenuItem
   301тЖТ              disabled
   302тЖТ              text={`... and ${peakPeriods.length - 3} more`}
   303тЖТ              className={Classes.TEXT_MUTED}
   304тЖТ            />
   305тЖТ          )}
   306тЖТ          <MenuDivider />
   307тЖТ        </>
   308тЖТ      )}
   309тЖТ
   310тЖТ      {/* Recommendations */}
   311тЖТ      {recommendations.length > 0 && (
   312тЖТ        <>
   313тЖТ          <MenuItem disabled text="Recommendations" icon="lightbulb" />
   314тЖТ          {recommendations.slice(0, 3).map((rec, idx) => (
   315тЖТ            <RecommendationItem key={idx} rec={rec} />
   316тЖТ          ))}
   317тЖТ          {recommendations.length > 3 && (
   318тЖТ            <MenuItem
   319тЖТ              disabled
   320тЖТ              text={`... and ${recommendations.length - 3} more`}
   321тЖТ              className={Classes.TEXT_MUTED}
   322тЖТ            />
   323тЖТ          )}
   324тЖТ          <MenuDivider />
   325тЖТ        </>
   326тЖТ      )}
   327тЖТ
   328тЖТ      {/* Actions */}
   329тЖТ      <MenuItem icon="refresh" text="Refresh Analysis" onClick={onRefresh} />
   330тЖТ      <MenuItem icon="chart" text="View Full Report" />
   331тЖТ    </Menu>
   332тЖТ  );
   333тЖТ}
   334тЖТ
   335тЖТ// =============================================================================
   336тЖТ// Main Component
   337тЖТ// =============================================================================
   338тЖТ
   339тЖТexport function BowWaveIndicator({
   340тЖТ  compact = false,
   341тЖТ  fleetId,
   342тЖТ  planId,
   343тЖТ  className,
   344тЖТ}: BowWaveIndicatorProps) {
   345тЖТ  const { state: rawState, actions } = useOverlay();
   346тЖТ  const state = rawState as unknown as OverlaySliceState;
   347тЖТ
   348тЖТ  // Check URL params for chaos monkey on first render (deferred to avoid render-time effects)
   349тЖТ  // This only runs once since chaosMonkeyEnabled state persists
   350тЖТ  if (
   351тЖТ    typeof window !== 'undefined' &&
   352тЖТ    !state.chaosMonkeyEnabled &&
   353тЖТ    state.bowWaveLastFetch === null
   354тЖТ  ) {
   355тЖТ    const urlChaos = isChaosMonkeyEnabled();
   356тЖТ    if (urlChaos) {
   357тЖТ      // Defer state update to next microtask to avoid render-time side effects
   358тЖТ      Promise.resolve().then(() => {
   359тЖТ        actions.setChaosMonkeyEnabled(true);
   360тЖТ      });
   361тЖТ    }
   362тЖТ  }
   363тЖТ
   364тЖТ  // Load data callback
   365тЖТ  const loadData = () => {
   366тЖТ    loadBowWaveOverlayData(
   367тЖТ      {
   368тЖТ        setBowWaveLoading: actions.setBowWaveLoading,
   369тЖТ        setBowWaveData: actions.setBowWaveData,
   370тЖТ        setBowWaveError: actions.setBowWaveError,
   371тЖТ      },
   372тЖТ      { fleetId, planId, chaosMonkey: state.chaosMonkeyEnabled }
   373тЖТ    );
   374тЖТ  };
   375тЖТ
   376тЖТ  // Handle Shift+Click to toggle chaos monkey (hidden demo feature)
   377тЖТ  const handleClick = (e: React.MouseEvent) => {
   378тЖТ    if (e.shiftKey) {
   379тЖТ      e.preventDefault();
   380тЖТ      e.stopPropagation();
   381тЖТ
   382тЖТ      const newEnabled = !state.chaosMonkeyEnabled;
   383тЖТ      actions.toggleChaosMonkey();
   384тЖТ      toggleChaosMonkeyUrl(newEnabled);
   385тЖТ
   386тЖТ      // Reload data with new chaos state
   387тЖТ      Promise.resolve().then(loadData);
   388тЖТ    }
   389тЖТ  };
   390тЖТ
   391тЖТ  // Auto-load data on initial render if never loaded
   392тЖТ  // Conditions: never fetched, not currently loading, no data, and no error
   393тЖТ  // The error check prevents infinite retry loops when the API is unavailable
   394тЖТ  const shouldAutoLoad =
   395тЖТ    state.bowWaveLastFetch === null &&
   396тЖТ    !state.bowWaveLoading &&
   397тЖТ    state.bowWaveData === null &&
   398тЖТ    state.bowWaveError === null;
   399тЖТ
   400тЖТ  if (shouldAutoLoad) {
   401тЖТ    // Defer load to next microtask to avoid state updates during render
   402тЖТ    Promise.resolve().then(loadData);
   403тЖТ  }
   404тЖТ
   405тЖТ  const riskDisplay = selectBowWaveRiskDisplay(state);
   406тЖТ  const intent = state.chaosMonkeyEnabled ? 'danger' : RISK_INTENT_MAP[riskDisplay.level];
   407тЖТ  const icon = state.chaosMonkeyEnabled ? 'flame' : RISK_ICON_MAP[riskDisplay.level];
   408тЖТ
   409тЖТ  // Loading state
   410тЖТ  if (state.bowWaveLoading && !state.bowWaveData) {
   411тЖТ    return (
   412тЖТ      <Tag minimal className={className}>
   413тЖТ        <Spinner size={12} />
   414тЖТ        <span style={{ marginLeft: 6 }}>Loading...</span>
   415тЖТ      </Tag>
   416тЖТ    );
