/**
 * MMS Infinite Canvas
 *
 * The main canvas component that renders PM schedule data at different zoom levels.
 * Uses deck.gl for strategic view (WebGL) and Konva for tactical/operational views (Canvas 2D).
 *
 * Zoom Level Rendering:
 * - STRATEGIC (0-4): deck.gl WebGL heatmap
 * - TACTICAL_WIDE (4-8): deck.gl WebGL compressed blocks
 * - TACTICAL (8-12): Konva HTML5 Canvas Gantt
 * - OPERATIONAL (12-16): Konva HTML5 Canvas detailed cards
 * - DETAIL (16+): React DOM overlay
 *
 * Based on specs/006-user-interface.md Section 6.3.
 */

import { useRef } from 'react';
import { Card, NonIdealState, Spinner, Tag, Button, ButtonGroup, OverlayToaster, Intent, Position } from '@blueprintjs/core';

import { useCanvas, useCanvasData, useFleet, usePm, useUi, useOverlay, loadStrategicData, loadTacticalData, loadTacticalWideData, loadOperationalData, loadDetailData, loadBaselineShadowData } from '../../store';
import type { CanvasSliceState } from '../../store/slices/canvas';
import type { CanvasDataState } from '../../store/slices/canvas';
import type { FleetSliceState } from '../../store/slices/fleet';
import type { PmSliceState } from '../../store/slices/pm';
import type { UiSliceState } from '../../store/slices/ui';
import type { OverlaySliceState } from '../../store/slices/overlay';
import type { ZoomLevel } from '../../store/types';
import { StrategicHeatmapLayer, TacticalWideLayer, TacticalGanttLayer, OperationalDetailLayer, DetailCardOverlay, type HeatmapCell, type PmBlock, type OperationalPmBlock, type DragValidationState, type PmMoveImpact } from './layers';
import { DragConfirmationDialog } from './DragConfirmationDialog';
import {
  quickValidatePmMove,
  createDebouncedValidation,
  getPmMoveImpact,
  commitPmMove,
  createCanvasKeyboardHandler,
  type KeyboardHandlerCallbacks,
  // Accessibility utilities
  initializeAnnouncer,
  announceZoomChange,
  announcePmDeselection,
  prefersReducedMotion,
  onReducedMotionChange,
  FOCUS_RING_STYLES,
} from './utils';
import { KeyboardShortcutsDialog } from '../KeyboardShortcutsDialog';
import { Minimap } from './Minimap';

// Toaster helper for showing notifications
// Uses the static show method which handles async creation
async function showToast(options: {
  intent: typeof Intent[keyof typeof Intent];
  icon: 'error' | 'tick' | 'warning-sign' | 'info-sign';
  message: string;
  timeout: number;
}): Promise<void> {
  const toaster = await OverlayToaster.createAsync({ position: Position.TOP_RIGHT });
  toaster.show(options);
}

/** Default canvas dimensions when container size is not available */
const DEFAULT_CANVAS_WIDTH = 1200;
const DEFAULT_CANVAS_HEIGHT = 800;

// Drag confirmation state interface
interface DragConfirmState {
  isOpen: boolean;
  pmId: string | null;
  pmCode: string;
  trainNumber: string;
  sourceDate: string;
  targetDate: string;
  impact: PmMoveImpact | null;
  isLoadingImpact: boolean;
}

const initialDragConfirmState: DragConfirmState = {
  isOpen: false,
  pmId: null,
  pmCode: '',
  trainNumber: '',
  sourceDate: '',
  targetDate: '',
  impact: null,
  isLoadingImpact: false,
};

export function InfiniteCanvas() {
  const { state: canvasStateRaw, actions: canvasActions } = useCanvas();
  const { state: canvasDataStateRaw, actions: canvasDataActions } = useCanvasData();
  const { state: fleetStateRaw } = useFleet();
  const { state: pmStateRaw, actions: pmActions } = usePm();
  const { state: uiStateRaw, actions: uiActions } = useUi();
  const { state: overlayStateRaw, actions: overlayActions } = useOverlay();

  const canvasState = canvasStateRaw as unknown as CanvasSliceState;
  const canvasDataState = canvasDataStateRaw as unknown as CanvasDataState;
  const fleetState = fleetStateRaw as unknown as FleetSliceState;
  const pmState = pmStateRaw as unknown as PmSliceState;
  const uiState = uiStateRaw as unknown as UiSliceState;
  const overlayState = overlayStateRaw as unknown as OverlaySliceState;

  const { zoom, zoomLevel, viewport, isPanning, layers } = canvasState;
  const {
    strategicData, strategicLoading, strategicError, fromYear, toYear,
    tacticalWideData, tacticalWideLoading, tacticalWideError, tacticalWideFromDate, tacticalWideToDate,
    tacticalData, tacticalLoading, tacticalError, tacticalFromDate, tacticalToDate,
    operationalData, operationalLoading, operationalError, operationalFromDate, operationalToDate,
    detailData, detailLoading, detailError, detailFromDate, detailToDate, detailExpandedPmIds
  } = canvasDataState;
  const isLoading = fleetState.trains.length === 0;

  const tooltipPosRef = useRef<{ x: number; y: number }>({ x: 0, y: 0 });
  const tooltipRef = useRef<HTMLDivElement>(null);

  // Drag state refs
  const dragValidationRef = useRef<DragValidationState | null>(null);
  const draggingPmRef = useRef<{
    pmId: string;
    pmCode: string;
    trainId: string;
    trainNumber: string;
    sourceDate: string;
    constraintStart: string;
    constraintEnd: string;
    isLocked: boolean;
  } | null>(null);
  const dragConfirmRef = useRef<DragConfirmState>(initialDragConfirmState);

  // Create debounced API validation
  const debouncedValidationRef = useRef(
    createDebouncedValidation((result) => {
      dragValidationRef.current = result;
      if (draggingPmRef.current) {
        pmActions.setDragValidation({
          isValid: result.isValid,
          message: result.message,
          violations: result.violations,
        });
      }
    }, { delay: 150 })
  );

  // Ref for container to handle focus
  const containerRef = useRef<HTMLDivElement>(null);

  // Accessibility refs
  const isKeyboardNavigationRef = useRef(false);
  const announcerInitializedRef = useRef(false);
  const reducedMotionCleanupRef = useRef<(() => void) | null>(null);

